// Extract message — FULL REPLACE v3 (adds audio detection + hasAudio)
// Input: $json.body.updates[0]
// Output: { text, chatId, login, hasFile, hasAudio, files[] }

function normalizeText(s) {
  return String(s || '').replace(/\u00A0/g, ' ').trim();
}

function toArrayMaybe(x) {
  if (!x) return [];
  if (Array.isArray(x)) return x;
  return [x];
}

function uniqPushFile(arr, f) {
  const kind = String(f.kind || '');
  const id = String(f.file_id || f.id || '');
  const key = `${kind}|${id}`;
  if (!id) return;
  if (arr._seen && arr._seen.has(key)) return;
  arr._seen = arr._seen || new Set();
  arr._seen.add(key);
  arr.push(f);
}

function guessKindByName(name) {
  const n = String(name || '').toLowerCase();
  if (/\.(png|jpg|jpeg|bmp|gif|tif|tiff|webp)$/i.test(n)) return 'image';
  if (/\.(ogg|opus|mp3|wav|m4a|aac|flac)$/i.test(n)) return 'audio';
  return 'file';
}

const update = $json?.body?.updates?.[0];
if (!update) return [];

const text = normalizeText(update.text || '') || 'Empty';

// chatId/login
const chatId = update?.from?.id ?? update?.chat?.id ?? null;
const login = update?.from?.login ?? null;

const files = [];

// images can come in different shapes: images[0] array, images array, or object
const imagesRaw = update.images;
if (imagesRaw) {
  // sometimes images is [[...]] or [...]
  const imgs = Array.isArray(imagesRaw) && Array.isArray(imagesRaw[0]) ? imagesRaw[0] : imagesRaw;
  for (const src of toArrayMaybe(imgs)) {
    if (!src) continue;
    const file_id = src.file_id || src.id;
    uniqPushFile(files, {
      kind: 'image',
      file_id,
      name: src.name || '',
      size: src.size,
      width: src.width,
      height: src.height,
    });
  }
}

// generic file (docs, logs, voice, etc)
if (update.file) {
  const f = update.file;
  const file_id = f.file_id || f.id;
  const name = f.name || '';
  const kind = guessKindByName(name);
  uniqPushFile(files, {
    kind,
    file_id,
    name,
    size: f.size,
  });
}

const hasFile = files.length > 0;
const hasAudio = files.some(f => String(f.kind).toLowerCase() === 'audio');

return [{
  json: {
    text,
    chatId,
    login,
    hasFile,
    hasAudio,
    files,
  }
}];

// Prepare reply — FULL REPLACE v2-B (LOGparser)
// - Always returns TXT file with final report
// - File name: "<archiveBase>.txt" (fallback logparser_report.txt)
// - Preserves chatId/login; sendText splitting handled by downstream If file + Send Text/Send file nodes

function s(x){ return x == null ? '' : String(x); }

function normalizeChatId(chatId) {
  if (!chatId) return null;
  const t = String(chatId).trim();
  return t.includes('/') ? t : `0/0/${t}`;
}

function extractAssistantText(j) {
  if (!j || typeof j !== 'object') return '';
  if (typeof j.message?.content === 'string') return j.message.content;
  if (typeof j.ollama?.message?.content === 'string') return j.ollama.message.content;
  if (typeof j.response === 'string') return j.response;
  if (typeof j.text === 'string') return j.text;
  return '';
}

function stripThink(raw) {
  return s(raw).replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
}

function baseName(name) {
  const t = s(name).trim();
  if (!t) return 'logparser_report';
  const just = t.split(/[\\/]/).pop();
  return just.replace(/\.(zip|tgz|tar\.gz|gz|tar|7z)$/i, '');
}

const base = $input.item.json || {};
const chatId = normalizeChatId(base.chatId || base.chat_id);
const login = base.login || base.user || null;

const content = stripThink(extractAssistantText(base)).trim() || stripThink(s(base.message?.content)).trim();
const fileBase = baseName(base.sourceFileName || base.archiveName || base.fileName || (Array.isArray(base.files) && base.files[0] && base.files[0].name) || '');
const outName = `${fileBase}.txt`;

// Add UTF-8 BOM (Excel-friendly if needed)
const bom = Buffer.from([0xEF,0xBB,0xBF]);
const buf = Buffer.concat([bom, Buffer.from(content || 'N/A', 'utf8')]);

return [{
  json: {
    ...base,
    chatId,
    login,
    fileName: outName,
    isFile: true,
  },
  binary: {
    file: {
      data: buf.toString('base64'),
      fileName: outName,
      mimeType: 'text/plain; charset=utf-8',
    }
  }
}];

// Code node "Stop"
// Ничего не делаем и останавливаем цепочку для этих сообщений
return [];

// LLM2 Storage Structure Extract — FULL REPLACE v13.1 (ME/MSA store_logs first + exact CLI block capture)
// Purpose:
// - Strong Tier1 for Dell ME4012 / ME5024 / HPE MSA2040
// - Search exact CLI blocks inside store_*.logs first:
//   # show enclosures
//   # show redundancy-mode
//   # show versions detail
//   # show controllers / # show controller
// - Tier2 always included, capped to 40k chars
// - Total evidence cap 200k
// - Tier1 hits/term 20, Tier2 hits/term 5, dedup max 3
//
// Expected result:
// - For ME/MSA family, Enclosures/Controllers must come from store_*.logs blocks, not from generic keyword noise.

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const base = $input.item.json || {};
const s = (x) => (x == null ? '' : String(x));
const low = (x) => s(x).toLowerCase();

const SRC = s(base.combinedLogPath).trim();

const TMP_ROOT = s($env.LOGPARSER_LLM_TMP_ROOT || '/home/node/.n8n/tmp/logparser_evidence').trim() || '/home/node/.n8n/tmp/logparser_evidence';
const TTL_HOURS = Number($env.LOGPARSER_LLM_TTL_HOURS || 72);

const TOTAL_MAX_CHARS = Number($env.LLM2_EVIDENCE_MAX_CHARS || 200000);
const TIER2_MAX_CHARS = Number($env.LLM2_TIER2_MAX_CHARS || 40000);

const DEDUP_MAX = Number($env.LLM2_DEDUP_MAX_REPEAT || 3);
const TIER1_MAX_HITS_PER_TERM = Number($env.LLM2_TIER1_MAX_HITS_PER_TERM || 20);
const TIER2_MAX_HITS_PER_TERM = Number($env.LLM2_TIER2_MAX_HITS_PER_TERM || 5);

// -------- helpers --------
function fileExists(p){ try { return !!p && fs.existsSync(p) && fs.statSync(p).isFile(); } catch { return false; } }
function ensureDir(p){ try { fs.mkdirSync(p, { recursive:true }); } catch {} }

function cleanupOld(root, ttlHours){
  try {
    if (!fs.existsSync(root)) return;
    const now = Date.now();
    const ttlMs = Math.max(1, ttlHours) * 3600 * 1000;
    for (const name of fs.readdirSync(root)) {
      const p = path.join(root, name);
      let st;
      try { st = fs.statSync(p); } catch { continue; }
      if (!st.isDirectory()) continue;
      if ((now - Number(st.mtimeMs || 0)) > ttlMs) {
        try { fs.rmSync(p, { recursive:true, force:true }); } catch {}
      }
    }
  } catch {}
}

function safeBaseName(name){
  const t = s(name).trim();
  if (!t) return 'archive';
  const just = t.split(/[\\/]/).pop();
  return just
    .replace(/\.(zip|tgz|tar\.gz|gz|tar|7z|tbz2|tar\.bz2|bz2)$/i, '')
    .replace(/[^\w.\-]+/g, '_')
    .slice(0, 120) || 'archive';
}

function pickRunToken(b){
  const t = s(b.combinedLogToken || '').trim();
  if (t) return t.replace(/[^\w.\-]+/g, '_').slice(0, 80);
  const f = s(b.sourceFileId || '').trim();
  if (f) return ('fid_' + f.replace(/[^\w.\-]+/g, '_').slice(0, 60));
  return `${Date.now()}_${crypto.randomBytes(6).toString('hex')}`;
}

function writeTmpText(b, tag, text){
  cleanupOld(TMP_ROOT, TTL_HOURS);
  ensureDir(TMP_ROOT);
  const runToken = pickRunToken(b);
  const srcBase = safeBaseName(
    b.sourceFileName || b.archiveName || b.fileName ||
    (Array.isArray(b.files) && b.files[0] && b.files[0].name) || ''
  );
  const dir = path.join(TMP_ROOT, `run_${runToken}`);
  ensureDir(dir);
  const fn = `${srcBase}__${tag}.txt`.replace(/[^\w.\-]+/g, '_').slice(0, 180);
  const fp = path.join(dir, fn);
  fs.writeFileSync(fp, s(text), 'utf8');
  return fp;
}

function readLinesStream(fp, onLine){
  const fd = fs.openSync(fp, 'r');
  const BUF = Buffer.alloc(1024 * 1024);
  let carry = '';
  try {
    while (true) {
      const n = fs.readSync(fd, BUF, 0, BUF.length, null);
      if (!n) break;
      const chunk = carry + BUF.slice(0, n).toString('utf8');
      const parts = chunk.split(/\r?\n/);
      carry = parts.pop() || '';
      for (const ln of parts) onLine(ln);
    }
    if (carry) onLine(carry);
  } finally {
    try { fs.closeSync(fd); } catch {}
  }
}

function normKey(line){
  return s(line).trim().replace(/\s+/g, ' ').toLowerCase();
}

function makeDeduper(maxRepeat){
  const counts = new Map();
  let removed = 0;
  return {
    ok(line){
      const k = normKey(line);
      if (!k) return false;
      const c = counts.get(k) || 0;
      if (c >= maxRepeat) { removed++; return false; }
      counts.set(k, c + 1);
      return true;
    },
    removed(){ return removed; }
  };
}

function makeSafeAppender(maxChars){
  let total = 0;
  const parts = [];
  return {
    push(line){
      const t = s(line);
      if (!t) return true;
      const add = t.length + 1;
      if (total + add > maxChars) return false;
      parts.push(t);
      total += add;
      return true;
    },
    text(){ return parts.join('\n'); },
    size(){ return total; },
  };
}

function makeHitLimiter(maxHits){
  const map = new Map();
  return {
    hit(term){
      const k = String(term || '').toLowerCase();
      const c = map.get(k) || 0;
      if (c >= maxHits) return false;
      map.set(k, c + 1);
      return true;
    },
    toJSON(){
      const o = {};
      for (const [k,v] of map.entries()) o[k] = v;
      return o;
    }
  };
}

// ---- noise filters ----
const NOISE_RE = [
  /Failure to find value for key:/i,
  /\[object Arguments\]/i,
  /SERIALNUMBER=\$SERIALNUMBER/i,
  /\bget_perf\b/i,
  /\bSNMP locked IP\b/i,
  /\bNTP server status\b/i,
];
function isNoise(line){
  const t = s(line);
  if (!t.trim()) return true;
  if (NOISE_RE.some(r => r.test(t))) return true;
  return false;
}

// ---- vendor flags ----
const vendor = low(base.hw_vendor || base.vendor || '');
const modelHw = low(base.hw_model || base.modelDetected || base.model || '');
const isME_MSA = /me4|me5|me4012|me4024|me4084|me5024|msa\s*2040/i.test(modelHw);

// ---- Tier1 exact CLI block capture for ME/MSA in store_*.logs ----
function captureStoreCliBlocks(fp, out, dedup){
  const targets = [
    { name:'SHOW_ENCLOSURES', marker:/^\[?source.*store_.*\.logs.*\]?\s*#\s*show\s+enclosures\b/i, maxLines:9000 },
    { name:'SHOW_REDUNDANCY', marker:/^\[?source.*store_.*\.logs.*\]?\s*#\s*show\s+redundancy-mode\b/i, maxLines:4000 },
    { name:'SHOW_VERSIONS',   marker:/^\[?source.*store_.*\.logs.*\]?\s*#\s*show\s+versions\s+detail\b/i, maxLines:7000 },
    { name:'SHOW_CONTROLLERS',marker:/^\[?source.*store_.*\.logs.*\]?\s*#\s*show\s+controllers?\b/i, maxLines:7000 },

    // fallback if source-prefix stripped in combinedLog
    { name:'SHOW_ENCLOSURES_FALLBACK', marker:/^#\s*show\s+enclosures\b/i, maxLines:9000 },
    { name:'SHOW_REDUNDANCY_FALLBACK', marker:/^#\s*show\s+redundancy-mode\b/i, maxLines:4000 },
    { name:'SHOW_VERSIONS_FALLBACK',   marker:/^#\s*show\s+versions\s+detail\b/i, maxLines:7000 },
    { name:'SHOW_CONTROLLERS_FALLBACK',marker:/^#\s*show\s+controllers?\b/i, maxLines:7000 },
  ];

  const states = targets.map(t => ({...t, active:false, done:false, lines:[]}));

  function startIf(trimmed, line){
    for (const st of states) {
      if (!st.done && !st.active && st.marker.test(trimmed)) {
        st.active = true;
        st.lines.push(line);
      }
    }
  }

  readLinesStream(fp, (raw) => {
    const line = s(raw).replace(/\r/g,'');
    const tr = line.trim();

    startIf(tr, line);

    for (const st of states) {
      if (!st.active || st.done) continue;

      if (!(st.lines.length === 1 && st.marker.test(tr))) st.lines.push(line);

      if (/^Success:\s*Command completed/i.test(tr)) { st.done = true; st.active = false; continue; }

      // stop on next command
      if (st.lines.length > 3 && /^#\s+\w+/i.test(tr) && !st.marker.test(tr)) {
        st.lines.pop();
        st.done = true; st.active = false; continue;
      }

      if (st.lines.length >= st.maxLines) { st.done = true; st.active = false; continue; }
    }
  });

  for (const st of states) {
    const body = st.lines.join('\n').trim();
    if (!body) continue;
    out.push(`=== TIER1 CLI ${st.name} ===`);
    for (const ln of body.split('\n')) {
      const t = ln.replace(/\r/g,'');
      if (!t.trim()) continue;
      if (dedup.ok(`[TIER1] ${t}`)) out.push(`[TIER1] ${t}`);
    }
    out.push('');
  }
}

// ---- generic Tier2 windows (always) ----
const TIER2_TERMS = [
  'enclosure', 'encl', 'chassis', 'shelf',
  'controller', 'storage processor', 'sp a', 'sp b',
  'enclwwn', 'serial', 'midplane', 'emp a', 'emp b',
].map(x => x.toLowerCase());

function captureTier2(fp, outApp, dedup, hitCounts){
  const limiter = makeHitLimiter(TIER2_MAX_HITS_PER_TERM);
  const ring = [];
  let after = 0;

  function push(line){
    const tagged = `[TIER2] ${line}`;
    if (isNoise(tagged)) return;
    if (!dedup.ok(tagged)) return;
    if (!outApp.push(tagged)) return;
  }

  readLinesStream(fp, (raw) => {
    if (outApp.size() >= TIER2_MAX_CHARS) return;
    const line = s(raw).replace(/\r/g,'');
    const l = line.toLowerCase();

    let term = '';
    for (const t of TIER2_TERMS) {
      if (l.includes(t)) { term = t; break; }
    }

    if (term && limiter.hit(term)) {
      for (const prev of ring) push(prev);
      push(line);
      after = 3;
    } else if (after > 0) {
      push(line);
      after--;
    }

    ring.push(line);
    if (ring.length > 3) ring.shift();
  });

  Object.assign(hitCounts, limiter.toJSON());
}

// ---- main ----
if (!fileExists(SRC)) {
  const msg = `[n8n] LLM2 Structure Extract: combinedLogPath missing/unreadable: ${SRC || 'N/A'}`;
  const snipPath = writeTmpText(base, 'llm2_structure_evidence', msg);
  return [{
    json: {
      ...base,
      llm2_snip_path: snipPath,
      llm2_snip_chars: msg.length,
      llm2_extract_mode: 'error_missing_combinedLogPath',
      llm2_extract_dedup_removed: 0,
      llm2_tier1_hit_counts: {},
      llm2_tier2_hit_counts: {},
      digest_structure_text: '',
      llm2_structure_preview: msg.slice(0, 1200),
    }
  }];
}

const dedup = makeDeduper(DEDUP_MAX);
const tier1Out = [];
const tier2HitsObj = {};

if (isME_MSA) {
  captureStoreCliBlocks(SRC, tier1Out, dedup);
}

let evidenceParts = [];
const tier1Text = tier1Out.join('\n').trim();
evidenceParts.push(`=== TIER1 (HIGH PRIORITY / TRUST FIRST) ===\n${tier1Text || '[n8n] Tier1: no strong blocks found.'}`);

const tier2App = makeSafeAppender(TIER2_MAX_CHARS);
captureTier2(SRC, tier2App, dedup, tier2HitsObj);
evidenceParts.push(`=== TIER2 (LOW PRIORITY / USE ONLY IF MISSING IN TIER1) ===\n${tier2App.text().trim() || '[n8n] Tier2: no hits.'}`);

let evidence = evidenceParts.join('\n\n').trim();
if (evidence.length > TOTAL_MAX_CHARS) evidence = evidence.slice(0, TOTAL_MAX_CHARS) + '\n[n8n] TRUNCATED';

const snipPath = writeTmpText(base, 'llm2_structure_evidence', evidence);

return [{
  json: {
    ...base,
    llm2_snip_path: snipPath,
    llm2_snip_chars: evidence.length,
    llm2_extract_mode: 'v13.1-me-msa-storelogs-cli-blocks-tier2-always-40k',
    llm2_extract_dedup_removed: dedup.removed(),
    llm2_tier1_hit_counts: {}, // Tier1 here is block-capture, not term-count based
    llm2_tier2_hit_counts: tier2HitsObj,
    digest_structure_text: '',
    llm2_structure_preview: evidence.slice(0, 1200),
  }
}];

// Storage Disks Extract — FULL REPLACE v15.0
// Tier1-first, vendor-aware, strengthened for:
// - Huawei OceanStore / Dorado: showsds / CTE/DAE rows / Serial Number / Barcode
// - Dell ME4012 exact header
// - HPE MSA 2040 exact header
// - IBM FlashSystem lsdrive -delim :
// - HPE 3PAR showpd
// - EMC VNX getdisk / Bus Enclosure Disk
//
// Rules:
// - Scan whole combinedLogPath
// - Tier1 only looks for real disk tables / row-only inventory blocks
// - Tier2 runs ONLY if Tier1 text <= 5000 chars
// - Dedup up to 3 repeats
// - Final digest capped to 200000 chars

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const base = $input.item.json || {};
const s = (x) => (x == null ? '' : String(x));

const TMP_ROOT = s($env.LOGPARSER_LLM_TMP_ROOT || '/home/node/.n8n/tmp/logparser_evidence').trim() || '/home/node/.n8n/tmp/logparser_evidence';
const TTL_HOURS = Number($env.LOGPARSER_LLM_TTL_HOURS || 72);

const MAX_OUTPUT_CHARS = Number($env.LLM3_MAX_OUTPUT_CHARS || 200000);
const MAX_BLOCK_LINES  = Number($env.LLM3_MAX_BLOCK_LINES || 12000);
const MAX_BLOCK_CHARS  = Number($env.LLM3_MAX_BLOCK_CHARS || 500000);
const MAX_BLOCKS_T1    = Number($env.LLM3_T1_MAX_BLOCKS || 12);
const MAX_BLOCKS_T2    = Number($env.LLM3_T2_MAX_BLOCKS || 8);
const DUP_MAX          = Number($env.LOGPARSER_MAX_REPEAT_LINES || 3);
const PREVIEW_CHARS    = 6000;
const TIER1_SKIP_TIER2_IF_GT = Number($env.LLM3_TIER1_SKIP_TIER2_IF_GT || 5000);

function ensureDir(p){ try { fs.mkdirSync(p, { recursive:true }); } catch {} }
function cleanupOld(root, ttlHours){
  try{
    if (!fs.existsSync(root)) return;
    const now = Date.now();
    for (const name of fs.readdirSync(root)) {
      const p = path.join(root, name);
      let st; try { st = fs.statSync(p); } catch { continue; }
      if (!st.isDirectory()) continue;
      const ageH = (now - st.mtimeMs) / 3600000;
      if (ageH > ttlHours) { try { fs.rmSync(p, { recursive:true, force:true }); } catch {} }
    }
  } catch {}
}
function safeBaseName(name){
  const t = s(name).trim();
  if (!t) return 'archive';
  const just = t.split(/[\\/]/).pop();
  return just
    .replace(/\.(zip|tgz|tar\.gz|gz|tar|7z|tbz2|tar\.bz2|bz2|xz|txz|zst|tzst|rar)$/i,'')
    .replace(/[^\w.\-]+/g,'_')
    .slice(0,120) || 'archive';
}
function pickRunToken(b){
  const t = s(b.combinedLogToken || '').trim();
  if (t) return t.replace(/[^\w.\-]+/g,'_').slice(0,80);
  const f = s(b.sourceFileId || '').trim();
  if (f) return ('fid_' + f.replace(/[^\w.\-]+/g,'_').slice(0,60));
  return `${Date.now()}_${crypto.randomBytes(6).toString('hex')}`;
}
function writeTempFile(b, tag, content){
  cleanupOld(TMP_ROOT, TTL_HOURS);
  ensureDir(TMP_ROOT);
  const runToken = pickRunToken(b);
  const srcBase = safeBaseName(b.sourceFileName || b.archiveName || b.fileName || '');
  const dir = path.join(TMP_ROOT, `run_${runToken}`);
  ensureDir(dir);
  const fn = `${srcBase}__${tag}.txt`.replace(/[^\w.\-]+/g,'_').slice(0,180);
