const RX_NOISE = /\b(recommend|troubleshoot|if\s+the\s+alarm|contact\s+support|knowledge\s+base|kb\s*:|redundancy\s+and\s+failover|chapter\s+\d+|copyright|authentication|unauthorized|login|timeout|oauth|token|webhook|http)\b/i;

function looksSep(t){
  const x = s(t).trim();
  return !!x && (/^[-=]{6,}$/.test(x) || /^[\-\s]{12,}$/.test(x) || /^\+[-+]{6,}\+$/.test(x));
}
function colonCount(t){ return (s(t).match(/:/g) || []).length; }
function looksColonRow(t){
  const x = s(t);
  if (colonCount(x) < 6) return false;
  if (/https?:\/\//i.test(x)) return false;
  return true;
}
function looksTabRow(t){
  const x = s(t).trimEnd();
  if (!x) return false;
  if (looksSep(x)) return true;
  if (x.includes('|') || x.includes(';')) return true;
  if (looksColonRow(x)) return true;
  if (/\s{2,}\S+/.test(x)) return true;
  return false;
}

// ===== Tier1 exact signatures =====

// Dell ME / ME4012 exact formats
const T1_ME_CMD = /^#\s*show\s+disks\b/i;
const T1_ME_ROW = /^\s*\d+\.\d+\s+\S+/;
const T1_ME4012_HDR = /^\s*enclosure_id\s+slot\s+disk_id\s+serial_number\s+part_number\s+model\s+vendor\s+size_gb\s+type\s+speed_rpm\s+state\s+health\s+firmware\b/i;
const T1_ME4012_ROW = /^\s*\d+\.\d+\s+\S+\s+\S+\s+\S+\s+\S+/;

// HPE MSA exact formats
const T1_MSA_CMD = /^#\s*show\s+disks\b/i;
const T1_MSA_HDR1 = /^\s*enclosure_id\s+slot\s+disk_id\s+serial_number\s+part_number\s+model\s+vendor\s+size_gb\s+type\s+speed_rpm\s+state\s+health\b/i;
const T1_MSA_HDR2 = /^\s*Location\s+SerialNumber\s+Vendor\s+Description\s+Usage\s+SpeedKRPM\s+Size\s+SecFmt\s+DiskGroup\s+Pool\s+Tier\s+Health\b/i;
const T1_MSA_ROW  = /^\s*\d+\.\d+\s+\S+\s+\S+\s+\S+/;

// Huawei OceanStore / Dorado
const T1_HUA_CMD = /diagnose>\s*ld\s+showsds\b/i;
const T1_HUA_HDR = /^\s*ID\s+LDID\s+SDID\s+Serial\s+Number\s+Barcode\b/i;
const T1_HUA_ROW = /^\s*(CTE|DAE)\d+\.\d+\s+\d+\s+\d+\s+\S+/i;

// IBM FlashSystem / SVC
const T1_IBM_CMD = /\bsvcinfo\s+lsdrive\s+-delim\s*:\b/i;
const T1_IBM_HDR = /^\s*id:status:.*:capacity:.*(enclosure_id|slot_id)/i;
const T1_IBM_ROW = /^\s*\d+:(online|offline|degraded|failed|unknown)?\b/i;

// HPE 3PAR
const T1_3PAR_HDR = /^\s*Id\s+CagePos\s+Type\s+State\b/i;
const T1_3PAR_ROW = /^\s*\d+\s+\d+:\d+:\d+\s+\S+\s+\S+/i;

// EMC VNX
const T1_VNX_HDR1 = /\bBus\s+Enclosure\s+Disk\b/i;
const T1_VNX_HDR2 = /\bnaviseccli\b.*\bgetdisk\b/i;
const T1_VNX_ROW  = /^\s*\d+\s+\d+\s+\d+\s+\S+/;

const RX_DISK_HDR_STRICT = /\b(serial\s*number|serial\b|sn\b|part\s*number|pn\b|vendor\b|manufacturer\b|capacity\b|size\b|slot\b|cagepos\b|enclosure\b|drive_id\b|disk_id\b|health\b|state\b|status\b)\b/i;

function t1Start(t){
  if (!t || RX_NOISE.test(t)) return false;

  if (T1_ME_CMD.test(t) || T1_ME4012_HDR.test(t)) return true;
  if (T1_MSA_CMD.test(t) || T1_MSA_HDR1.test(t) || T1_MSA_HDR2.test(t)) return true;
  if (T1_HUA_CMD.test(t) || T1_HUA_HDR.test(t)) return true;
  if (T1_IBM_CMD.test(t) || T1_IBM_HDR.test(t)) return true;
  if (T1_3PAR_HDR.test(t)) return true;
  if (T1_VNX_HDR1.test(t) || T1_VNX_HDR2.test(t)) return true;

  // row-only starts
  if (T1_ME_ROW.test(t) || T1_ME4012_ROW.test(t) || T1_MSA_ROW.test(t) || T1_HUA_ROW.test(t) || T1_IBM_ROW.test(t) || T1_3PAR_ROW.test(t) || T1_VNX_ROW.test(t)) return true;

  if (looksTabRow(t) && RX_DISK_HDR_STRICT.test(t)) return true;
  return false;
}

function t1Row(t){
  if (!t || RX_NOISE.test(t)) return false;
  if (T1_ME_ROW.test(t) || T1_ME4012_ROW.test(t) || T1_MSA_ROW.test(t) || T1_HUA_ROW.test(t) || T1_IBM_ROW.test(t) || T1_3PAR_ROW.test(t) || T1_VNX_ROW.test(t)) return true;
  if (looksColonRow(t) && /\b(online|offline|degraded|failed|member|spare|unused)\b/i.test(t)) return true;
  return false;
}

function t1Tag(t){
  if (T1_HUA_HDR.test(t) || T1_HUA_ROW.test(t) || T1_HUA_CMD.test(t)) return 'Huawei showsds';
  if (T1_IBM_HDR.test(t) || T1_IBM_ROW.test(t) || T1_IBM_CMD.test(t)) return 'IBM lsdrive -delim :';
  if (T1_3PAR_HDR.test(t) || T1_3PAR_ROW.test(t)) return 'HPE 3PAR showpd';
  if (T1_VNX_HDR1.test(t) || T1_VNX_HDR2.test(t) || T1_VNX_ROW.test(t)) return 'EMC VNX getdisk';
  if (T1_MSA_HDR1.test(t) || T1_MSA_HDR2.test(t) || T1_MSA_ROW.test(t) || T1_MSA_CMD.test(t)) return 'HPE MSA disks';
  if (T1_ME4012_HDR.test(t) || T1_ME4012_ROW.test(t) || T1_ME_CMD.test(t) || T1_ME_ROW.test(t)) return 'Dell ME disks';
  return 'Generic Tier1';
}

function scoreBlock(lines){
  let rows = 0;
  for (const ln of lines) if (t1Row(ln)) rows++;

  let score = rows * 3;
  const joined = lines.join('\n');

  if (joined.match(/diagnose>\s*ld\s+showsds/i)) score += 50;
  if (joined.match(/svcinfo\s+lsdrive\s+-delim\s*:/i)) score += 45;
  if (lines.some(l => T1_3PAR_HDR.test(l))) score += 35;
  if (joined.match(/Bus\s+Enclosure\s+Disk/i) || joined.match(/naviseccli.*getdisk/i)) score += 30;
  if (lines.some(l => T1_MSA_HDR1.test(l) || T1_MSA_HDR2.test(l))) score += 30;
  if (lines.some(l => T1_ME4012_HDR.test(l))) score += 30;
  if (joined.match(/^#\s*show\s+disks/m)) score += 20;

  if (/\bTB\b|\bGB\b|\bTiB\b|\bGiB\b/i.test(joined)) score += 4;
  if (/\bserial\b|\bsn\b/i.test(joined)) score += 4;
  if (/\bpart\b|\bpn\b/i.test(joined)) score += 3;
  if (/\bstatus\b|\bstate\b|\bhealth\b|\bonline\b|\boffline\b/i.test(joined)) score += 3;
  if (lines.some(looksSep)) score += 2;

  const nonTab = lines.filter(l => l && !looksTabRow(l) && !t1Row(l) && !RX_DISK_HDR_STRICT.test(l)).length;
  score -= Math.min(15, Math.floor(nonTab / 20));

  return { score, rows };
}

async function scanTier(filePath, tierName){
  return await new Promise((resolve, reject) => {
    const rs = fs.createReadStream(filePath, { encoding:'utf8' });
    let bytes = 0;
    let linesRead = 0;
    let buf = '';

    let cur = null;
    const blocks = [];

    function closeCur(reason){
      if (!cur) return;
      while (cur.lines.length && !s(cur.lines[cur.lines.length - 1]).trim()) cur.lines.pop();

      const sc = scoreBlock(cur.lines);
      const ok = (sc.rows >= 4) || /Huawei|IBM|HPE 3PAR|EMC VNX|HPE MSA|Dell ME/.test(cur.tag);

      if (ok) {
        blocks.push({
          lines: cur.lines.slice(),
          chars: cur.chars,
          score: sc.score,
          rows: sc.rows,
          tag: cur.tag,
          reason,
        });
      }
      cur = null;
    }

    function startBlock(t){
      closeCur('new_start');
      cur = { lines: [], chars: 0, tag: tierName === 'T1' ? t1Tag(t) : 'Generic Tier2' };
      pushLine(t);
    }

    function pushLine(t){
      if (!cur) return;
      if (cur.lines.length >= MAX_BLOCK_LINES) return;
      if (cur.chars >= MAX_BLOCK_CHARS) return;
      cur.lines.push(t);
      cur.chars += t.length + 1;
    }

    function shouldEnd(t){
      if (!cur) return false;
      if (!t.trim()) return cur.lines.length > 50;
      if (tierName === 'T1' && t1Start(t) && cur.lines.length > 20) return true;
      if (tierName !== 'T1' && looksTabRow(t) && RX_DISK_HDR_STRICT.test(t) && cur.lines.length > 20) return true;
      if (/^\s*#\s*(show|exit|set|cd)\b/i.test(t) && cur.lines.length > 10) return true;
      if (RX_NOISE.test(t) && cur.lines.length > 20) return true;
      return false;
    }

    function t2Start(t){
      if (!t || RX_NOISE.test(t)) return false;
      return looksTabRow(t) && RX_DISK_HDR_STRICT.test(t);
    }
    function t2Row(t){
      if (!t || RX_NOISE.test(t)) return false;
      if (!looksTabRow(t)) return false;
      const hasPos = /\b\d+[:.]\d+\b/.test(t) || /\bslot\b|\bcage\b|\bencl/i.test(t) || /\b(CTE|DAE)\d+\.\d+\b/i.test(t);
      const hasSer = /\b[A-Z0-9]{7,}\b/.test(t) || /\bserial\b|\bsn\b/i.test(t);
      const hasCap = /\b(\d+(\.\d+)?)(\s*)?(TB|GB|TiB|GiB)\b/i.test(t) || /\bcapacity\b|\bsize\b/i.test(t);
      const hasState = /\b(online|offline|ok|normal|failed|degraded|unknown)\b/i.test(t);
      const c = (hasPos?1:0) + (hasSer?1:0) + (hasCap?1:0) + (hasState?1:0);
      return c >= 2;
    }

    rs.on('data', (chunk) => {
      bytes += Buffer.byteLength(chunk, 'utf8');
      buf += chunk;

      let idx;
      while ((idx = buf.indexOf('\n')) >= 0) {
        const raw = buf.slice(0, idx);
        buf = buf.slice(idx + 1);
        linesRead++;

        const t = norm(raw);
        if (!t) {
          if (cur && cur.lines.length && cur.lines[cur.lines.length - 1] !== '') pushLine('');
          continue;
        }
        if (t.length > 9000) continue;
        if (RX_NOISE.test(t)) continue;

        if (!cur) {
          if (tierName === 'T1') {
            if (t1Start(t)) startBlock(t);
          } else {
            if (t2Start(t)) startBlock(t);
          }
          continue;
        }

        if (shouldEnd(t)) {
          closeCur('end');
          if (tierName === 'T1') { if (t1Start(t)) startBlock(t); }
          else { if (t2Start(t)) startBlock(t); }
          continue;
        }

        if (tierName === 'T1') {
          const keep = looksTabRow(t) || t1Row(t) || RX_DISK_HDR_STRICT.test(t);
          if (keep) pushLine(t);
        } else {
          const keep = looksTabRow(t) || t2Row(t) || RX_DISK_HDR_STRICT.test(t);
          if (keep) pushLine(t);
        }
      }
    });

    rs.on('close', () => {
      closeCur('eof');
      blocks.sort((a,b)=> (b.score - a.score) || (b.rows - a.rows) || (a.chars - b.chars));
      resolve({ bytesRead: bytes, linesRead, blocks });
    });

    rs.on('error', reject);
  });
}

function packBlocks(blocks, maxBlocks, label){
  const used = [];
  let over = 0;
  for (const b of blocks.slice(0, maxBlocks)) {
    const head = `=== ${label} (${b.tag}) score=${b.score} rows=${b.rows} lines=${b.lines.length} ===`;
    const body = b.lines.join('\n').trim();
    if (!body) continue;
    const pack = `${head}\n${body}`.trim();
    used.push(pack);
    over += pack.length + 2;
    if (over > MAX_OUTPUT_CHARS * 3) break;
  }
  return used.join('\n\n').trim();
}

