function parseTables(text) {
  const out = [];
  const t = stripThink(s(text)).replace(/\r/g, '');
  const lines = t.split('\n');

  let cur = null;

  function pushCur() {
    if (!cur) return;
    while (cur.lines.length && !s(cur.lines[cur.lines.length - 1]).trim()) cur.lines.pop();
    out.push(cur);
    cur = null;
  }

  for (const raw of lines) {
    const line = raw.trimEnd();
    const m = line.match(/^\s*TABLE:\s*(.+?)\s*$/i);
    if (m) {
      pushCur();
      cur = { name: s(m[1]).trim(), lines: [] };
      continue;
    }
    if (!cur) continue;

    const tr = line.trim();
    if (!tr) continue;

    if (/^N\/A$/i.test(tr)) { cur.lines.push('N/A'); continue; }
    cur.lines.push(line.trim());
  }
  pushCur();
  return out;
}

function isNAOnly(tableLines) {
  if (!tableLines || !tableLines.length) return true;
  if (tableLines.length === 1 && /^N\/A$/i.test(tableLines[0].trim())) return true;
  return false;
