function parseSemicolonTable(lines) {
  const rows = [];
  for (const ln of (lines || [])) {
    const t = s(ln).trim();
    if (!t) continue;
    if (/^N\/A$/i.test(t)) return { header: null, rows: [] };

    if (t.includes(';')) rows.push(t.split(';').map(x => s(x).trim()));
    else rows.push(t.split(/\s{2,}/).map(x => s(x).trim()));
  }
  if (!rows.length) return { header: null, rows: [] };

  const first = rows[0];
  const alphaish = first.filter(c => /[a-zа-я]/i.test(c)).length;
  const numericish = first.filter(c => /^\d+(\.\d+)?$/.test(c)).length;

  let header = null;
  let body = rows;

  if (first.length >= 2 && alphaish >= Math.max(2, Math.floor(first.length / 2)) && numericish <= Math.floor(first.length / 3)) {
    header = first;
    body = rows.slice(1);
  }

  return { header, rows: body };
}

function dropEmptyColumns(header, rows) {
  const colCount = Math.max(
    header ? header.length : 0,
    ...rows.map(r => r.length),
    0
  );
  if (!colCount) return { header, rows };

  const normRows = rows.map(r => {
    const rr = r.slice();
    while (rr.length < colCount) rr.push('');
    return rr;
  });

  const normHeader = header ? (() => {
    const hh = header.slice();
    while (hh.length < colCount) hh.push('');
    return hh;
  })() : null;

  const keep = new Array(colCount).fill(false);
  for (let c = 0; c < colCount; c++) {
    if (normHeader && normalizeNA(normHeader[c])) keep[c] = true;
    for (const r of normRows) {
      if (normalizeNA(r[c])) { keep[c] = true; break; }
    }
  }

  if (!keep.some(Boolean)) keep[0] = true;

  function filterArr(arr) {
    const out = [];
    for (let c = 0; c < colCount; c++) if (keep[c]) out.push(s(arr[c] || ''));
    return out;
  }

  return {
    header: normHeader ? filterArr(normHeader) : null,
    rows: normRows
      .map(filterArr)
      .filter(r => r.some(cell => normalizeNA(cell))),
  };
