  for (const r of rows) all.push(r);

  const colCount = Math.max(...all.map(a => a.length), 0);
  const widths = new Array(colCount).fill(0);

  for (const r of all) {
    for (let i = 0; i < colCount; i++) {
      const cell = s(r[i] || '');
      widths[i] = Math.max(widths[i], cell.length);
    }
  }

  function fmtRow(r) {
    const parts = [];
    for (let i = 0; i < colCount; i++) {
      const cell = s(r[i] || '');
      parts.push(cell.padEnd(widths[i], ' '));
    }
    return parts.join('  ').trimEnd();
  }

  const out = [];
  if (header) {
    out.push(fmtRow(header));
    out.push(widths.map(w => '-'.repeat(Math.max(3, Math.min(w, 40)))).join('  ').trimEnd());
