function formatFixedSchemaTable(tableNamePrinted, tableLines, fixedHeaderStr) {
  if (isNAOnly(tableLines)) return `TABLE: ${tableNamePrinted}\nN/A`;

  const { rows } = parseSemicolonTable(tableLines);
  const fixedHeader = fixedHeaderStr.split(';');

  const outRows = (rows || [])
    .map(r => {
      const rr = r.slice();
      while (rr.length < fixedHeader.length) rr.push('N/A');
      if (rr.length > fixedHeader.length) rr.length = fixedHeader.length;
      return rr.map(x => {
        const v = s(x || '').trim();
        return v ? v : 'N/A';
      });
    })
