function formatTableBlock(tableName, tableLines) {
  const name = s(tableName).trim();

  // DISKS: fixed schema, no column hiding
  if (/^disks$/i.test(name)) {
    return formatDisksTable(tableLines);
  }

  // LLM4/LLM5 universal fixed-schema tables (no column hiding)
  if (/^powersupplies$/i.test(name)) {
    return formatFixedSchemaTable('PowerSupplies', tableLines, PSU_UNI_HEADER);
  }
  if (/^sfp$/i.test(name)) {
    return formatFixedSchemaTable('SFP', tableLines, SFP_UNI_HEADER);
  }
  if (/^bbu$/i.test(name)) {
    return formatFixedSchemaTable('BBU', tableLines, BBU_UNI_HEADER);
  }
  if (/^fans$/i.test(name)) {
    return formatFixedSchemaTable('Fans', tableLines, FANS_UNI_HEADER);
  }

  // default behaviour for other tables
  if (isNAOnly(tableLines)) return `TABLE: ${name}\nN/A`;

  const { header, rows } = parseSemicolonTable(tableLines);
  const dropped = dropEmptyColumns(header, rows);
  const text = toAlignedTextTable(dropped.header, dropped.rows);

  if (!text) return `TABLE: ${name}\nN/A`;
  return `TABLE: ${name}\n${text}`;
}

function extractAndFormatTables(text, wantedNames /* array or null */) {
  const tables = parseTables(text);
  const out = [];
  for (const t of tables) {
    const name = s(t.name);
    if (wantedNames && wantedNames.length) {
      const hit = wantedNames.some(w => String(w).toLowerCase() === name.toLowerCase());
      if (!hit) continue;
    }
    out.push(formatTableBlock(name, t.lines));
  }
  return out;
}

function findByTaskLike(predFn) {
  for (const it of items) {
    const j = it?.json || {};
    const msg = pickMessageContent(j);
    if (predFn({ ...j, _msg: msg })) return j;
  }
  return null;
}

function bestTextFor(kind) {
  const j = findByTaskLike((x) => {
    const t = s(x.task).toLowerCase();
    const msg = s(x._msg || '');

    if (kind === 'structure') return t.includes('structure') || (/TABLE:\s*Enclosures/i.test(msg) && /TABLE:\s*Controllers/i.test(msg));
    if (kind === 'disks') return t.includes('disks') || /TABLE:\s*Disks\b/i.test(msg);
    if (kind === 'psu_sfp') return t.includes('psu') || t.includes('sfp') || (/TABLE:\s*PowerSupplies\b/i.test(msg) || /TABLE:\s*SFP\b/i.test(msg));
    if (kind === 'bbu_fan') return t.includes('bbu') || t.includes('fan') || (/TABLE:\s*BBU\b/i.test(msg) || /TABLE:\s*Fans\b/i.test(msg));

    if (kind === 'errors') {
      return (t.includes('errors') || /TABLE:\s*Errors\b/i.test(msg) || /^\s*Errors\s*$/im.test(msg) || /^\s*Parser metadata\s*$/im.test(msg));
