    _errors_samples_used: blocks.length,
    _errors_compose_version: 'v11-file-input-like-llm2',
  }
}];

// Prepare prompt — FULL REPLACE v1.2 (set ReportLLM default to deepseek-r1:32b-qwen-distill-fp16)
