function s(x){ return x == null ? '' : String(x); }

function isImageFile(f){
  const kind = s(f?.kind).toLowerCase();
  if (kind === 'image') return true;
  const name = s(f?.name).toLowerCase();
  return /\.(png|jpg|jpeg|webp|bmp|tiff|gif)$/i.test(name);
}

function scoreAttachment(f){
  const name = s(f?.name).toLowerCase();
  let sc = 0;
  if (/\.(zip|tar\.gz|tgz|tar|gz|7z|tbz2|bz2|xz|zst)$/i.test(name)) sc += 50;
  if (/\.(log|logs|txt|csv|xml|json)$/i.test(name)) sc += 10;
  const size = Number(f?.size);
  if (Number.isFinite(size)) sc += Math.min(20, Math.floor(size / 5_000_000));
  return sc;
}

function toTs(r){
  const t = Number(r?.timestamp);
  if (Number.isFinite(t) && t > 0) return t;
  const c = Number(r?.createdAt);
  if (Number.isFinite(c) && c > 0) return c;
  return 0;
}

function parseFiles(v){
  if (!v) return [];
  if (Array.isArray(v)) return v;
  if (typeof v === 'string') {
    try { const j = JSON.parse(v); return Array.isArray(j) ? j : []; } catch { return []; }
  }
  return [];
}

function nowMSK(){
  try {
    const dt = new Date();
    const f = new Intl.DateTimeFormat('ru-RU', {
      timeZone: 'Europe/Moscow',
      year:'numeric', month:'2-digit', day:'2-digit',
      hour:'2-digit', minute:'2-digit', second:'2-digit',
      hour12:false
    }).formatToParts(dt).reduce((a,p)=>{a[p.type]=p.value; return a;},{});
    return `${f.hour}:${f.minute}:${f.second} ${f.day}-${f.month}-${f.year} (MSK)`;
  } catch {
    const d = new Date(Date.now() + 3*3600*1000);
    return d.toISOString().replace('T',' ').replace('Z','') + ' (MSK~)';
  }
}

// Read messages returns multiple items
const rows = $input.all().map(it => it.json || {});
if (!rows.length) return [];

rows.sort((a,b) => toTs(a) - toTs(b));

const withFiles = rows.map(r => {
