  String.raw`<\s*(product|model|vendor|manufacturer|serial|part)[^>]*>`,
  // Versions
  String.raw`\b(firmware|FW|version|build|release|OS)\b`,
  // CLI
  String.raw`(?:^|\s)#\s*show\s+`
].join('|'), 'i');

const RX_STRONG = new RegExp([
  String.raw`\b(ME4\d{3}|ME5\d{3}|ME\d{4}|MD38\d{2}0F|VNX\d{3,4}|MSA\s?\d{3,4}|3PAR|OceanStor|Dorado|ONTAP|Storwize|FlashSystem)\b`,
  String.raw`\b(productId|scsiVendorId)\b`,
  String.raw`<\s*model\b`,
  String.raw`\b(Product\s*Name|System\s*Name|Chassis\s*Type)\b`
].join('|'), 'i');

function dedupBoundedPush(out, counts, line) {
  const t = s(line).trimEnd();
  if (!t) {
    if (out.length && out[out.length - 1] !== '') out.push('');
    return true;
  }
  const c = (counts.get(t) || 0) + 1;
  counts.set(t, c);
  if (c <= MAX_REPEAT) { out.push(t); return true; }
  return false;
}

function readHead(fp, maxBytes) {
  try {
    const fd = fs.openSync(fp, 'r');
    const b = Buffer.alloc(maxBytes);
    const got = fs.readSync(fd, b, 0, b.length, 0);
    fs.closeSync(fd);
    return b.slice(0, got).toString('utf8').replace(/\u0000/g,'');
  } catch { return ''; }
}
function readTail(fp, maxBytes) {
  try {
    const st = fs.statSync(fp);
    if (!st.isFile() || st.size <= 0) return '';
    const start = Math.max(0, st.size - maxBytes);
    const fd = fs.openSync(fp, 'r');
    const b = Buffer.alloc(st.size - start);
    const got = fs.readSync(fd, b, 0, b.length, start);
    fs.closeSync(fd);
    return b.slice(0, got).toString('utf8').replace(/\u0000/g,'');
  } catch { return ''; }
}

async function buildIdentifySnippet(fp, fileSize) {
  return new Promise((resolve, reject) => {
    const rs = fs.createReadStream(fp, { encoding: 'utf8' });

    let carry = '';
    let lineNo = 0;

    const ring = [];
    const out = [];
    const counts = new Map();

    let pendingAfter = 0;
    let matches = 0;
    let chars = 0;
    let seenStrong = 0;
    let stopReason = '';
    let scannedBytesApprox = 0;

    function addLine(line) {
      if (chars >= MAX_CHARS) return false;
      const ok = dedupBoundedPush(out, counts, line);
      if (ok) chars += (s(line).length + 1);
      return chars < MAX_CHARS;
    }

    function earlyStopCheck() {
      if (chars >= TARGET_CHARS) { stopReason = 'target_chars_reached'; return true; }
      if (matches >= MAX_MATCHES) { stopReason = 'max_matches_reached'; return true; }
      if (seenStrong >= 3 && chars >= Math.min(TARGET_CHARS, 200000)) { stopReason = 'strong_anchors_enough'; return true; }
      if (matches === 0 && scannedBytesApprox >= MAX_SCAN_BYTES_NOHIT) { stopReason = 'no_hits_fast_stop'; return true; }
      return false;
    }

    function handleLine(raw) {
      lineNo++;
      const line = raw.replace(/\r/g, '');

      if (CTX_BEFORE > 0) {
        ring.push(line);
        if (ring.length > CTX_BEFORE) ring.shift();
      }

      if (pendingAfter > 0) {
        addLine(line);
        pendingAfter--;
      }

      if (RX_HIT.test(line)) {
        matches++;
        if (RX_STRONG.test(line)) seenStrong++;

        if (CTX_BEFORE > 0) {
          const before = ring.slice(0, Math.max(0, ring.length - 1));
          for (const b of before) addLine(b);
        }

        addLine(line);
        pendingAfter = Math.max(pendingAfter, CTX_AFTER);
      }

      if (earlyStopCheck()) {
        try { rs.destroy(); } catch {}
      }
    }

    rs.on('data', (chunk) => {
      scannedBytesApprox += Buffer.byteLength(chunk, 'utf8');

      carry += chunk;
      let idx;
      while ((idx = carry.indexOf('\n')) >= 0) {
        const line = carry.slice(0, idx);
        carry = carry.slice(idx + 1);
        handleLine(line);
        if (stopReason) return;
      }

      if (earlyStopCheck()) {
        try { rs.destroy(); } catch {}
      }
    });

    rs.on('error', reject);

    rs.on('close', () => {
      if (!stopReason && carry) {
        try { handleLine(carry); } catch {}
      }

      let text = out.join('\n').trim();

      if (!text || matches === 0) {
        const head = readHead(fp, 350000);
        const tail = readTail(fp, 220000);
        text = `${head}\n\n[...NO IDENTIFY HITS; HEAD/TAIL FALLBACK...]\n\n${tail}`.trim();
        if (text.length > MAX_CHARS) text = text.slice(0, MAX_CHARS);
        if (!stopReason) stopReason = 'no_hits_head_tail_fallback';
      }

      resolve({
        text: text || 'N/A',
        stats: {
          file_size_bytes: Number(fileSize || 0),
          bytes_scanned_approx: scannedBytesApprox,
          lines_scanned: lineNo,
          matches,
          strong_hits: seenStrong,
          out_chars: (text || '').length,
          stop_reason: stopReason || 'eof',
          target_chars: TARGET_CHARS,
          max_chars: MAX_CHARS,
          max_matches: MAX_MATCHES,
          ctx_before: CTX_BEFORE,
          ctx_after: CTX_AFTER,
          max_repeat: MAX_REPEAT,
          max_scan_bytes_nohit: MAX_SCAN_BYTES_NOHIT,
        }
      });
    });
  });
}

const src = resolveCombinedPath(base);
