    const fd = fs.openSync(p, 'r');
    const b = Buffer.alloc(maxBytes);
    const got = fs.readSync(fd, b, 0, b.length, 0);
    fs.closeSync(fd);
    return b.slice(0, got).toString('utf8').replace(/\u0000/g, '');
  } catch {
