}

// ---------- Normalizers ----------
function normVendor(v, corpusText) {
  const raw = s(v).trim();
  const corp = s(corpusText);

  if (/\b(Huawei|OceanStor|Dorado)\b/i.test(corp) || /\b(Huawei|OceanStor|Dorado)\b/i.test(raw)) return 'Huawei';
  if (/\b(DellEMC|PowerVault|ME\d{4})\b/i.test(corp) || /\bPowerVault\b/i.test(raw) || /\bME\d{4}\b/i.test(raw)) return 'Dell EMC';
  if (/\b(EMC|VNX|Navisphere|Unisphere|CLARiiON|Unity)\b/i.test(corp) || /\bEMC\b/i.test(raw)) return 'EMC';
  if (/\b(IBM|Storwize|FlashSystem|Spectrum Virtualize|SVC)\b/i.test(corp) || /\bIBM\b/i.test(raw)) return 'IBM';
  if (/\b(HPE|3PAR|MSA)\b/i.test(corp) || /\bHPE\b/i.test(raw)) return 'HPE';
  if (/\b(NetApp|ONTAP|FAS|AFF)\b/i.test(corp) || /\bNetApp\b/i.test(raw)) return 'NetApp';
  if (/\bCisco\b/i.test(corp) || /\bCisco\b/i.test(raw)) return 'Cisco';
  if (/\bLenovo\b/i.test(corp) || /\bLenovo\b/i.test(raw)) return 'Lenovo';

  if (isMissingToken(raw)) return 'N/A';
  return raw || 'N/A';
}

function normClass(v, corpusText) {
  const raw = s(v).trim();
  const corp = s(corpusText);

  // ✅ rule from you: "Storage + anything" => Storage
  if (/\bstorage\b/i.test(raw) || /\bstorage\b/i.test(corp)) return 'Storage';

  if (isMissingToken(raw)) return 'N/A';
  const t = raw.toLowerCase();
  if (t.includes('stor')) return 'Storage';
  if (t.includes('serv')) return 'Server';
  if (t.includes('swit') || t.includes('network')) return 'Switch';
  if (t.includes('ups')) return 'UPS';
  if (t.includes('other')) return 'Other';
  return raw || 'N/A';
}

function normModel(v) {
  const raw = s(v).trim();
  if (isMissingToken(raw)) return 'N/A';
  return raw.replace(/\s+/g,' ').trim() || 'N/A';
}

// ---------- Content-only detection (Huawei precision) ----------
function detectVendorFromText(txt) {
  const t = s(txt);
  if (/\b(Huawei|OceanStor|Dorado)\b/i.test(t)) return 'Huawei';
  if (/\b(DellEMC|PowerVault|ME\d{4})\b/i.test(t)) return 'Dell EMC';
  if (/\b(EMC|VNX|Navisphere|Unisphere|CLARiiON|Unity)\b/i.test(t)) return 'EMC';
  if (/\b(IBM|Storwize|FlashSystem|Spectrum Virtualize|SVC)\b/i.test(t)) return 'IBM';
  if (/\b(HPE|3PAR|MSA)\b/i.test(t)) return 'HPE';
  if (/\b(NetApp|ONTAP)\b/i.test(t)) return 'NetApp';
  if (/\bCisco\b/i.test(t)) return 'Cisco';
  if (/\bLenovo\b/i.test(t)) return 'Lenovo';
  return 'N/A';
}

function detectClassFromText(txt) {
  const t = s(txt);
  if (/\bstorage\b/i.test(t)) return 'Storage';
  if (/\b(enclosure|controller|disk group|vdisk|virtual disk|pool|raid|sas|fc|iscsi)\b/i.test(t)) return 'Storage';
  return 'N/A';
}

function detectHuaweiOceanStorModel(txt) {
  const t = s(txt);

  // ✅ strongest: explicit "OceanStor 2600 V3" etc
  // supports: OceanStor 2600 V3 / OceanStor2600 V3 / OceanStor 2600V3 / Huawei 2600 V3
  let m =
    t.match(/\bOceanStor\s*([0-9]{3,5})\s*V([0-9]{1,2})\b/i) ||
    t.match(/\bOceanStor\s*([0-9]{3,5})V([0-9]{1,2})\b/i) ||
    t.match(/\bHuawei\s*([0-9]{3,5})\s*V([0-9]{1,2})\b/i);

  if (m && m[1] && m[2]) {
    const modelNum = String(m[1]);
    const ver = String(m[2]);
    return `OceanStor ${modelNum} V${ver}`;
  }

  // series-only fallback
  if (/\bOceanStor\s+V3\s+Series\b/i.test(t)) return 'OceanStor V3 Series';
  if (/\bOceanStor\s+V5\s+Series\b/i.test(t)) return 'OceanStor V5 Series';
  if (/\bOceanStor\s+V6\s+Series\b/i.test(t)) return 'OceanStor V6 Series';

  // sometimes appears as "V3 Series" without OceanStor word
  if (/\bV3\s+Series\b/i.test(t) && /\bHuawei\b/i.test(t)) return 'OceanStor V3 Series';

  return 'N/A';
}

