if (llmLooksBad) {
  if (vendor === 'N/A' && hv !== 'N/A') vendor = hv;
  if ((klass === 'N/A' || klass === 'Other') && hc !== 'N/A') klass = hc;
  if (model === 'N/A' && hm !== 'N/A') model = hm;
