function validateSchema(obj, evidenceText) {
  if (!obj || typeof obj !== 'object' || Array.isArray(obj)) return { ok:false, why:'not_object' };

  const keys = Object.keys(obj);
  const expected = ['vendor','class','model','confidence','evidence'];
  if (keys.length !== expected.length) return { ok:false, why:`keys_len_${keys.length}` };
  for (const k of expected) if (!keys.includes(k)) return { ok:false, why:`missing_${k}` };
  for (const k of keys) if (!expected.includes(k)) return { ok:false, why:`extra_${k}` };

  obj.vendor = normalizeVendor(obj.vendor);
  obj.class  = normalizeClass(obj.class);
  obj.model  = s(obj.model).trim() || 'N/A';

  const conf = Number(obj.confidence);
  if (!Number.isFinite(conf) || conf < 0 || conf > 100) return { ok:false, why:'bad_confidence' };

  if (!Array.isArray(obj.evidence)) return { ok:false, why:'evidence_not_array' };
  if (obj.evidence.length > 5) return { ok:false, why:'evidence_too_many' };

  // Evidence may be empty; but if present — should be literal substrings of evidenceText (soft check)
  const evText = s(evidenceText);
  for (const q of obj.evidence) {
    const qq = s(q).trim();
    if (!qq) continue;
    if (!evText.includes(qq)) return { ok:false, why:'evidence_quote_not_in_text' };
  }

  const essentialMissing = (obj.vendor === 'N/A' || obj.class === 'N/A' || obj.model === 'N/A');
  if (essentialMissing && conf > 40) return { ok:false, why:'conf_too_high_for_na' };

  return { ok:true, why:'' };
}

async function ollamaChat(model, system, user) {
