function buildEvidenceTwoTier(rawText, maxChars = 100000) {
  const text = s(rawText);
  const lines = text.split('\n');

  // Tier1: ultra-specific markers
  const rx1 = new RegExp([
    // Huawei Dorado generation
    String.raw`\bOceanStorDorado\s*6000\s*V[36]\b`,
    String.raw`\bOceanStorDorado6000V[36]\b`,
    String.raw`\bDorado\s*6000\s*V[36]\b`,
    String.raw`\bDorado6000V[36]\b`,

    // Dell ME4/ME5
    String.raw`\bPowerVault\s+ME\d{4}\b`,
    String.raw`\bME4\d{3}\b`,
    String.raw`\bME5\d{3}\b`,

    // HPE
    String.raw`\b3PAR\b`,
    String.raw`\bshowcage\b`,
    String.raw`\bshownode\b`,
    String.raw`\bMSA\s*\d{3,4}\b`,

    // EMC
    String.raw`\bVNX\d{0,4}\b`,
    String.raw`\bNavisphere\b`,
    String.raw`\bUnisphere\b`,
    String.raw`\bCLARiiON\b`,

    // IBM
    String.raw`\bStorwize\b`,
    String.raw`\bFlashSystem\b`,
    String.raw`\bSpectrum\s+Virtualize\b`,
    String.raw`\bSVC\b`,

    // NetApp
    String.raw`\bONTAP\b`,
    String.raw`\bFAS\d{3,4}\b`,
    String.raw`\bAFF\s?[A-Z]\d+\b`,
  ].join('|'), 'i');

  // Tier2: broad storage hints
  const rx2 = new RegExp([
    String.raw`\bstorage\b`,
    String.raw`\bstorage\s+array\b`,
    String.raw`\bcontroller\b`,
    String.raw`\benclosure\b`,
    String.raw`\bdisk\s*group\b`,
    String.raw`\bvdisk\b`,
    String.raw`\bvirtual\s+disk\b`,
    String.raw`\bpool\b`,
    String.raw`\bRAID\b`,
    String.raw`\biSCSI\b`,
    String.raw`\bFibre\s*Channel\b`,
    String.raw`\bSAS\b`,
  ].join('|'), 'i');

  const out = [];
  let chars = 0;

  function push(line) {
    if (!line) return;
    const add = line.length + 1;
    if (chars + add > maxChars) return false;
    out.push(line);
    chars += add;
    return true;
  }

  // Pass 1: Tier1
  for (const ln of lines) {
    if (rx1.test(ln)) {
      if (!push(ln)) break;
    }
  }

  // Pass 2: Tier2 (only if we still have space)
  if (chars < maxChars) {
    for (const ln of lines) {
      if (rx2.test(ln)) {
        if (!push(ln)) break;
      }
    }
  }

  // Fallback: head sample if nothing matched
  if (!out.length) {
    return clampStr(text, maxChars);
  }

  return out.join('\n');
}

async function main() {
  const model = 'deepseek-logs:latest'; // fixed
  const snippetPath = s(base.identify_snippet_path).trim();
  if (!snippetPath) {
    return [{ json: { ...base, _identify_llm_ok:false, _identify_llm_error:'identify_snippet_path is empty', identify_raw:'', ollama_text:'' } }];
  }

  let raw = safeReadAll(snippetPath);
  raw = maskPII(raw);

  // IMPORTANT: evidence max 100k
  let evidence = buildEvidenceTwoTier(raw, 100000);
  evidence = antiJsonLeak(evidence);

  const system = `ROLE: LOGPARSER IDENTIFY (NOT A CHATBOT)
Return ONLY one JSON object.
It MUST start with {"vendor": ... } and contain ONLY these 5 keys: vendor,class,model,confidence,evidence.
