    attempts.push({ i, ok: v.ok, why: v.why, txt_head: lastTxt.slice(0, 220) });

    if (v.ok) { lastObj = obj; break; }
    lastWhy = v.why;
  }

  const out = { ...base };
  out.ollama = { model, done_reason: 'stop', num_ctx: 65536, num_predict: 8192 };
  out.identify_runtime = {
    evidence_source: 'identify_snippet_path',
    evidence_chars_used: evidence.length,
    hard_max_chars: 100000,
