    out.identify_raw = JSON.stringify(fallback);
    out.ollama_text = out.identify_raw;
    out._identify_llm_ok = false;
    out._identify_llm_error = `schema validation failed after retries (${lastWhy || 'unknown'})`;
  }

  return [{ json: out }];
}

