function safeHeadText(buf, n = 160) {
  const b = Buffer.isBuffer(buf) ? buf : Buffer.from(String(buf || ''), 'utf8');
  return b.slice(0, n).toString('utf8').replace(/[^\x09\x0a\x0d\x20-\x7e]+/g, '.');
}

function pushTry(debug, row) {
  if (!debug || !Array.isArray(debug.getFileTries)) return;
  const next = { ...row };
  if (next.bodyHead) next.bodyHead = safeHeadText(next.bodyHead, 120);
  debug.getFileTries.push(next);
  if (debug.getFileTries.length > DEBUG_MAX_TRIES) debug.getFileTries.shift();
}

function httpRequestBuffer(urlString, opts = {}, bodyBuf = null) {
  return new Promise((resolve, reject) => {
    const req = https.request(urlString, opts, (res) => {
      const chunks = [];
      res.on('data', (d) => chunks.push(d));
      res.on('end', () => resolve({
        status: res.statusCode || 0,
        headers: res.headers || {},
        body: Buffer.concat(chunks),
      }));
    });
    req.on('error', reject);
    if (bodyBuf) req.write(bodyBuf);
    req.end();
  });
}

function httpDownloadToFile(urlString, opts = {}, outPath) {
  return new Promise((resolve, reject) => {
    ensureDir(path.dirname(outPath));
    const tmpPath = `${outPath}.part_${Date.now()}_${Math.random().toString(16).slice(2, 8)}`;

    const req = https.request(urlString, opts, (res) => {
      const status = res.statusCode || 0;
      const headers = res.headers || {};

      if (!(status >= 200 && status < 300)) {
        const chunks = [];
        res.on('data', d => chunks.push(d));
        res.on('end', () => {
          try { fs.rmSync(tmpPath, { force: true }); } catch {}
          resolve({ status, headers, bytes: 0, body: Buffer.concat(chunks) });
        });
        return;
      }

      const ws = fs.createWriteStream(tmpPath);
      let bytes = 0;

      res.on('data', (d) => { bytes += d.length; });

      ws.on('error', (e) => {
        try { fs.rmSync(tmpPath, { force: true }); } catch {}
        reject(e);
      });
      res.on('error', (e) => {
        try { ws.destroy(); } catch {}
        try { fs.rmSync(tmpPath, { force: true }); } catch {}
        reject(e);
      });

      ws.on('finish', () => {
        try { fs.renameSync(tmpPath, outPath); }
        catch (e) {
          try { fs.rmSync(tmpPath, { force: true }); } catch {}
          return reject(e);
        }
        resolve({ status, headers, bytes, body: Buffer.alloc(0) });
      });

      res.pipe(ws);
    });

    req.on('error', (e) => {
      try { fs.rmSync(tmpPath, { force: true }); } catch {}
      reject(e);
    });

    req.end();
  });
}

// ---------------- UTF + binary heuristics ----------------

function looksLikeUtf16ByBom(buf) {
  if (!buf || buf.length < 2) return null;
  const b0 = buf[0], b1 = buf[1];
  if (b0 === 0xff && b1 === 0xfe) return 'utf16le';
  if (b0 === 0xfe && b1 === 0xff) return 'utf16be';
  return null;
}

function looksLikeUtf8Bom(buf) {
  return !!(buf && buf.length >= 3 && buf[0] === 0xef && buf[1] === 0xbb && buf[2] === 0xbf);
}

function guessUtf16ByNulPattern(buf, sampleBytes = 65536) {
  if (!buf || buf.length < 8) return null;
  const n = Math.min(buf.length, sampleBytes);

  let zeros = 0, zerosEven = 0, zerosOdd = 0;
  for (let i = 0; i < n; i++) {
    if (buf[i] === 0x00) {
      zeros++;
      if ((i & 1) === 0) zerosEven++; else zerosOdd++;
    }
  }

  if (zeros < 64) return null;

  const zRatio = zeros / n;
  const evenShare = zerosEven / zeros;
  const oddShare = zerosOdd / zeros;

  if (zRatio >= 0.08 && (evenShare >= 0.70 || oddShare >= 0.70)) {
    return (oddShare >= 0.70) ? 'utf16le' : 'utf16be';
  }
  return null;
}

function isProbablyBinary(buf) {
  if (!buf || !buf.length) return true;

  if (looksLikeUtf16ByBom(buf)) return false;
  if (guessUtf16ByNulPattern(buf)) return false;

  const n = Math.min(buf.length, 65536);
  let bad = 0;

  for (let i = 0; i < n; i++) {
    const c = buf[i];
    if (c === 9 || c === 10 || c === 13) continue;
    if (c >= 32 && c <= 126) continue;
    if (c >= 0xC0) continue;
    if (c === 0x00) { bad += 4; continue; }
    if (c < 32) { bad += 1; continue; }
    if (c >= 0x7F && c <= 0xBF) { bad += 1; continue; }
  }

  return (bad / n) > 0.35;
}

function decodeSmart(buf) {
  if (!buf || !buf.length) return '';

  const bom16 = looksLikeUtf16ByBom(buf);
  if (bom16 === 'utf16le') {
    try { return buf.slice(2).toString('utf16le'); } catch {}
  }
  if (bom16 === 'utf16be') {
    try {
      const b = Buffer.from(buf.slice(2));
      b.swap16();
      return b.toString('utf16le');
    } catch {}
  }

  if (looksLikeUtf8Bom(buf)) {
    try { return buf.slice(3).toString('utf8'); } catch {}
  }

  const guess16 = guessUtf16ByNulPattern(buf);
  if (guess16 === 'utf16le') {
    try { return buf.toString('utf16le'); } catch {}
  }
  if (guess16 === 'utf16be') {
    try {
      const b = Buffer.from(buf);
      b.swap16();
      return b.toString('utf16le');
    } catch {}
  }

  try { return buf.toString('utf8'); } catch {}
  try { return buf.toString('latin1'); } catch {}
  return '';
}

// ---------------- VNX minipatch: chmod tree safe ----------------

function chmodTreeSafe(rootAbs, debug) {
  const touched = { files: 0, dirs: 0, errors: 0 };
  const root = s(rootAbs).trim();
  if (!root) return touched;

  const q = [root];
  const seen = new Set();

  while (q.length) {
    const cur = q.shift();
    const key = path.resolve(cur);
    if (seen.has(key)) continue;
    seen.add(key);

    let st;
    try { st = fs.lstatSync(cur); } catch { continue; }

    if (st.isDirectory()) {
      try { fs.chmodSync(cur, 0o755); touched.dirs++; } catch { touched.errors++; }
      let items = [];
      try { items = fs.readdirSync(cur, { withFileTypes: true }); } catch { continue; }
      for (const it of items) q.push(path.join(cur, it.name));
    } else if (st.isFile()) {
      try { fs.chmodSync(cur, 0o644); touched.files++; } catch { touched.errors++; }
    }
  }

  if (debug) debug.chmod_touched = touched;
  return touched;
}

// ---------------- Yandex getFile ----------------

async function yandexDownloadFileToPath(fileId, outPath, debug) {
  const token = s(env.YANDEX_BOT_TOKEN_LOGPARSER).trim();
  if (!token) throw new Error('Не настроен токен: заполните YANDEX_BOT_TOKEN_LOGPARSER');
  debug.tokenCandidates = ['YANDEX_BOT_TOKEN_LOGPARSER'];

  const fid = normalizeFileId(fileId);
  debug.file_id_raw = s(fileId);
  debug.file_id_norm = fid;
  if (!fid) throw new Error('Empty file_id after normalize');

  const endpoints = [
    { kind: 'files', post: 'https://botapi.messenger.yandex.net/bot/v1/files/getFile/', getBase: 'https://botapi.messenger.yandex.net/bot/v1/files/getFile' },
    { kind: 'messages', post: 'https://botapi.messenger.yandex.net/bot/v1/messages/getFile/', getBase: 'https://botapi.messenger.yandex.net/bot/v1/messages/getFile' },
  ];

  let lastErr = '';

  const writeBodyIfDirect = (resp, epKind, stepTag) => {
    if (!(resp.status >= 200 && resp.status < 300)) return { ok: false, wrote: 0 };
    const ct = String(resp.headers?.['content-type'] || '').toLowerCase();
    const body = resp.body || Buffer.alloc(0);

    const looksJson = ct.includes('application/json') || (body.length && body[0] === 0x7b);
    if (looksJson) {
      let obj = null;
      try { obj = JSON.parse(body.toString('utf8')); } catch {}
      if (obj && (obj.ok === false || obj.error || obj.description || obj.message)) {
        const errText = String(obj.description || obj.message || obj.error || 'json error');
        lastErr = `${epKind} ${stepTag}: ${errText}`;
        pushTry(debug, { step: `${stepTag}_json_error`, token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: epKind, err: errText });
      }
      return { ok: false, wrote: 0, jsonObj: obj };
    }

    if (body.length > 0) {
      fs.writeFileSync(outPath, body);
      return { ok: true, wrote: body.length };
    }

    lastErr = `${epKind} ${stepTag}: empty body`;
    return { ok: false, wrote: 0 };
  };

  for (const ep of endpoints) {
    // POST
    {
      const payload = Buffer.from(JSON.stringify({ file_id: fid }), 'utf8');
      let r1;
      try {
        r1 = await httpRequestBuffer(ep.post, {
          method: 'POST',
          headers: {
            'Authorization': `OAuth ${token}`,
            'Content-Type': 'application/json',
            'Content-Length': payload.length,
          },
        }, payload);
      } catch (e) {
        lastErr = e?.message || String(e);
        pushTry(debug, { step: 'post_exc', token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: ep.kind, apiUrl: ep.post, err: lastErr });
        r1 = null;
      }

      if (r1) {
        const bodyText = r1.body ? r1.body.toString('utf8') : '';
        pushTry(debug, { step: 'post', token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: ep.kind, apiUrl: ep.post, status: r1.status, bodyHead: bodyText });

        const direct = writeBodyIfDirect(r1, ep.kind, 'post');
        if (direct.ok) return direct.wrote;

        if (ep.kind === 'files' && r1.status >= 200 && r1.status < 300) {
          let obj = direct.jsonObj || {};
          try { if (!obj || typeof obj !== 'object') obj = JSON.parse(bodyText || '{}'); } catch { obj = {}; }
          const url = obj.url || obj.file_url || obj.download_url;
          if (url) {
            const r2 = await httpDownloadToFile(url, { method: 'GET' }, outPath);
            pushTry(debug, { step: 'files_url_get', token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: ep.kind, status: r2.status, bytes: r2.bytes || 0 });
            if (r2.status >= 200 && r2.status < 300 && (r2.bytes || 0) > 0) return r2.bytes || 0;
            lastErr = `download failed: HTTP ${r2.status}`;
          } else {
            lastErr = `files post HTTP ${r1.status}: empty download url`;
          }
        } else if (!(r1.status >= 200 && r1.status < 300)) {
          lastErr = `${ep.kind} post HTTP ${r1.status}`;
        }
      }
    }

    // GET
    {
      const url = `${ep.getBase}${ep.getBase.endsWith('/') ? '' : '/'}?file_id=${encodeURIComponent(fid)}`;
      let rG;
      try {
        rG = await httpRequestBuffer(url, {
          method: 'GET',
          headers: { 'Authorization': `OAuth ${token}` },
        }, null);
      } catch (e) {
        lastErr = e?.message || String(e);
        pushTry(debug, { step: 'get_exc', token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: ep.kind, apiUrl: url, err: lastErr });
        rG = null;
      }

      if (rG) {
        const bodyText = rG.body ? rG.body.toString('utf8') : '';
        pushTry(debug, { step: 'getFile_get', token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: ep.kind, apiUrl: url, status: rG.status, bodyHead: bodyText });

        const direct = writeBodyIfDirect(rG, ep.kind, 'get');
        if (direct.ok) return direct.wrote;

        if (ep.kind === 'files' && rG.status >= 200 && rG.status < 300) {
          let obj = direct.jsonObj || {};
          try { if (!obj || typeof obj !== 'object') obj = JSON.parse(bodyText || '{}'); } catch { obj = {}; }
          const dl = obj.url || obj.file_url || obj.download_url;
          if (dl) {
            const r2 = await httpDownloadToFile(dl, { method: 'GET' }, outPath);
            pushTry(debug, { step: 'files_url_get2', token: 'YANDEX_BOT_TOKEN_LOGPARSER', endpoint: ep.kind, status: r2.status, bytes: r2.bytes || 0 });
            if (r2.status >= 200 && r2.status < 300 && (r2.bytes || 0) > 0) return r2.bytes || 0;
            lastErr = `download failed: HTTP ${r2.status}`;
          } else {
            lastErr = `files get HTTP ${rG.status}: empty download url`;
          }
        } else if (!(rG.status >= 200 && rG.status < 300)) {
          lastErr = `${ep.kind} get HTTP ${rG.status}`;
        }
      }
    }
  }

  const triesSummary = (debug.getFileTries || [])
    .map(t => `${t.token || 'n/a'}:${t.endpoint || 'n/a'}:${t.step}:${t.status || t.err || 'n/a'}`)
    .slice(-12)
    .join(' | ');

  throw new Error(
    `Не удалось скачать архив из чата (file_id недоступен для YANDEX_BOT_TOKEN_LOGPARSER). ` +
    `${lastErr ? 'Последняя ошибка: ' + lastErr + '. ' : ''}` +
    `${triesSummary ? 'Трейс: ' + triesSummary : ''}`
  );
}

// ---------------- archive detection (magic-first) ----------------

function readHead(fileAbs, n = 4096) {
  try {
    const fd = fs.openSync(fileAbs, 'r');
    const b = Buffer.alloc(Math.max(0, n));
    const got = fs.readSync(fd, b, 0, b.length, 0);
    fs.closeSync(fd);
    return b.slice(0, got);
  } catch {
    return Buffer.alloc(0);
  }
}

function readAt(fileAbs, pos, n) {
  try {
    const fd = fs.openSync(fileAbs, 'r');
    const b = Buffer.alloc(Math.max(0, n));
    const got = fs.readSync(fd, b, 0, b.length, pos);
    fs.closeSync(fd);
    return b.slice(0, got);
  } catch {
    return Buffer.alloc(0);
  }
}

function detectArchiveMagic(fileAbs) {
  const h = readHead(fileAbs, 16);

  if (h.length >= 4 && h[0] === 0x50 && h[1] === 0x4b && h[2] === 0x03 && h[3] === 0x04) return 'zip';
  if (h.length >= 2 && h[0] === 0x1f && h[1] === 0x8b) return 'gzip';
  if (h.length >= 3 && h[0] === 0x42 && h[1] === 0x5a && h[2] === 0x68) return 'bzip2';
  if (h.length >= 6 && h[0] === 0xfd && h[1] === 0x37 && h[2] === 0x7a && h[3] === 0x58 && h[4] === 0x5a && h[5] === 0x00) return 'xz';
  if (h.length >= 4 && h[0] === 0x28 && h[1] === 0xB5 && h[2] === 0x2F && h[3] === 0xFD) return 'zstd';
  if (h.length >= 6 && h[0] === 0x37 && h[1] === 0x7a && h[2] === 0xbc && h[3] === 0xaf && h[4] === 0x27 && h[5] === 0x1c) return '7z';

  const t = readAt(fileAbs, 257, 5);
  if (t.length === 5 && t.toString('utf8') === 'ustar') return 'tar';

  return '';
}

function isArchiveByExt(fileAbs) {
  const ext = extLower(path.basename(fileAbs));
  return new Set([
    '.zip', '.7z',
    '.tar', '.gz', '.tgz', '.tar.gz',
    '.bz2', '.tbz', '.tbz2', '.tar.bz2',
    '.xz', '.txz', '.tar.xz',
    '.zst', '.tzst', '.tar.zst',
  ]).has(ext);
}

function isArchiveCandidate(fileAbs) {
  return !!detectArchiveMagic(fileAbs) || isArchiveByExt(fileAbs);
}

function ensureArchiveAliasForTools(fileAbs, aliasDir) {
  const magic = detectArchiveMagic(fileAbs);

  if (isArchiveByExt(fileAbs)) return { usePath: fileAbs, magic, aliased: false };

  const magicToExt = {
    zip: '.zip',
    gzip: '.gz',
    bzip2: '.bz2',
    xz: '.xz',
    zstd: '.zst',
    tar: '.tar',
    '7z': '.7z',
  };

  const forceExt = magicToExt[magic] || '';
  if (!forceExt) return { usePath: fileAbs, magic, aliased: false };

  ensureDir(aliasDir);

  let st;
  try { st = fs.statSync(fileAbs); } catch { st = null; }
  const sig = crypto.createHash('sha1')
    .update(`${path.resolve(fileAbs)}|${st?.size || 0}|${Math.trunc(st?.mtimeMs || 0)}|${magic}`)
    .digest('hex')
    .slice(0, 16);

  const aliasBase = safeName(path.basename(fileAbs)).slice(0, 80) || 'arc';
  const alias = path.join(aliasDir, `${aliasBase}.${sig}.__arc__${forceExt}`);

  if (!fs.existsSync(alias)) {
    try { fs.linkSync(fileAbs, alias); }
    catch { fs.copyFileSync(fileAbs, alias); }
  }

  return { usePath: alias, magic, aliased: true };
}

// ---------------- unzip-pack client ----------------

async function unzipPackExtract(archivePath, outDir, debug) {
  if (!UNZIP_PACK_URL) throw new Error('UNZIP_PACK_URL is empty');

  const url = `${UNZIP_PACK_URL}/archive/extract`;
  const body = {
    archive_path: archivePath,
    out_dir: outDir,
    overwrite: true,
    timeout_sec: Math.max(60, Math.floor(UNZIP_PACK_TIMEOUT_MS / 1000)),
    max_files: Math.max(1000, UNZIP_PACK_MAX_FILES),
  };

  let resp;
  try {
    resp = await self.helpers.httpRequest({
      method: 'POST',
      url,
      json: true,
      body,
      timeout: UNZIP_PACK_TIMEOUT_MS,
    });
  } catch (e) {
    debug.warnings.push(`unzip-pack request failed: ${path.basename(archivePath)}: ${e?.message || String(e)}`);
    return { ok: false, engine: '', code: -1, error: String(e?.message || e) };
  }

  const ok = !!resp?.ok;
  const out = {
    ok,
    engine: s(resp?.engine),
    code: Number(resp?.code ?? (ok ? 0 : -1)),
    timeout: !!resp?.timeout,
    too_many_files: !!resp?.too_many_files,
    file_count: Number(resp?.file_count || 0),
    stderr_tail: s(resp?.stderr_tail),
    stdout_tail: s(resp?.stdout_tail),
  };

  if (!ok) {
    const tail = (out.stderr_tail || out.stdout_tail || '').replace(/\s+/g, ' ').slice(0, 500);
    debug.warnings.push(`unzip-pack extract failed: ${path.basename(archivePath)} engine=${out.engine || 'n/a'} code=${out.code}${out.timeout ? ' timeout' : ''}${out.too_many_files ? ' too_many_files' : ''}${tail ? ` :: ${tail}` : ''}`);
  }

  return out;
}

// ---------------- file enumeration + combine ----------------

function listFilesRecursive(rootDir, maxFiles) {
  const out = [];
  const q = [rootDir];

  while (q.length) {
    const d = q.shift();
    let items = [];
    try { items = fs.readdirSync(d, { withFileTypes: true }); }
    catch { continue; }

    for (const it of items) {
      const abs = path.join(d, it.name);
      if (it.isDirectory()) q.push(abs);
      else out.push(abs);
      if (out.length >= maxFiles) return out;
    }
  }

  return out;
}

function collectFilesFromRoots(roots, maxFiles) {
  let out = [];
  for (const r of roots) {
    out = out.concat(listFilesRecursive(r, maxFiles));
    if (out.length >= maxFiles) break;
  }
  if (out.length > maxFiles) out = out.slice(0, maxFiles);
  return out;
}

function isHardBinaryExt(ext) {
  return new Set([
    '.jpg','.jpeg','.png','.gif','.bmp','.webp','.ico',
    '.mp3','.wav','.ogg','.mp4','.avi','.mkv','.mov',
    '.exe','.dll','.so','.dylib','.class','.jar','.pyc',
    '.bin','.img','.iso','.vmdk','.qcow2',
    '.rpm','.deb','.pkg','.msi',
    '.ttf','.otf','.woff','.woff2',
    '.sfw',
  ]).has(ext);
}

function isPreferredTextExt(ext) {
  return new Set([
    '.txt','.log','.out','.err','.trc','.trace','.evt','.csv',
    '.xml','.json','.yaml','.yml','.ini','.cfg','.conf',
    '.cli','.cmd','.lst','.dat','.asc',
    '.html','.htm'
  ]).has(ext);
}

function pathCategoryScore(abs) {
  const p = abs.toLowerCase().replace(/\\/g, '/');
  let score = 0;

  // high-priority dirs/files that usually hold useful structured evidence
  if (/(^|\/)(logs?\/cli|cli|show|status|supportshow|diag|diagnostic|config|configs|xml|json)(\/|$)/.test(p)) score += 120;
  if (/(show|status|config|xml|json|inventory|hardware|controller|enclosure|disk|raid|pool|vdisk)/.test(p)) score += 80;

  // periphery keywords for LLM4
  if (/(psu|power[-_ ]?supply|fans?|fan[-_ ]?control|sfp|transceiver|port[s]?|phy|iom|module)/.test(p)) score += 140;

  // noisy app/trace blobs should go later
  if (/(^|\/)(app|appsv|trace|debug|core|crash|dump|tmp|var)(\/|$)/.test(p)) score -= 120;
  if (/(appsv|messages(\.\d+)?|journal|debug|trace|telemetry|perf|stats)/.test(p)) score -= 80;

  return score;
}

function fileNameScore(abs) {
  const bn = path.basename(abs).toLowerCase();
  const ext = extLower(bn);
  let score = 0;

  if (isPreferredTextExt(ext)) score += 40;
  if (isHardBinaryExt(ext)) score -= 100;

  // Strong periphery anchors first (LLM4)
  if (/(show[-_ ]?power|power[-_ ]?suppl|psu|show[-_ ]?fans?|fan[-_ ]?control|show[-_ ]?ports?|sfp|transceiver)/i.test(bn)) score += 260;

  // LLM2/LLM3 useful anchors
  if (/(show[-_ ]?(enclosure|controller|disk|disks|vdisk|pool)|inventory|fru|sensor|alarm|event|status|config|health)/i.test(bn)) score += 180;

  // generic useful logs
  if (/(showeventlog|eventlog|event|alarm|alert|syslog|messages|support|collect|dump|log|trace|error|debug|history)/i.test(bn)) score += 30;
  if (/(xml|json|config|cfg|cli|status|health|storage|disk|raid|controller)/i.test(bn)) score += 20;

  // push giant app logs later
  if (/^appsv.*\.log(\.\w+)?$/i.test(bn)) score -= 260;
  if (/\.gz$/i.test(bn) && /(app|trace|debug|messages)/i.test(bn)) score -= 180;

  return score;
}

function scoreTextCandidate(abs) {
  let st = null;
  try { st = fs.statSync(abs); } catch {}
  const size = Number(st?.size || 0);
  const ext = extLower(abs);

  let score = 0;
  score += pathCategoryScore(abs);
  score += fileNameScore(abs);

  // size shaping: prefer medium structured files, push huge blobs later
  if (size > 0 && size <= 2 * 1024 * 1024) score += 40;           // <=2MB
  else if (size <= 20 * 1024 * 1024) score += 10;                 // <=20MB
  else if (size > 100 * 1024 * 1024) score -= 120;                // >100MB
  else if (size > 20 * 1024 * 1024) score -= 50;

  // text-ish ext bonus
  if (ext === '.xml' || ext === '.json' || ext === '.cfg' || ext === '.conf' || ext === '.cli') score += 35;

  return score;
}

function sortCandidatesForCombine(filesAbs) {
  return filesAbs.slice().sort((a, b) => {
    const sa = scoreTextCandidate(a);
    const sb = scoreTextCandidate(b);
    if (sb !== sa) return sb - sa;

    // tie-breaker: smaller first helps structured files surface earlier
    let as = 0, bs = 0;
    try { as = fs.statSync(a).size || 0; } catch {}
    try { bs = fs.statSync(b).size || 0; } catch {}
    if (as !== bs) return as - bs;

    const ea = extLower(a), eb = extLower(b);
    if (ea !== eb) return ea.localeCompare(eb);
    return a.localeCompare(b);
  });
}

function appendBlock(fd, header, text) {
  fs.writeSync(fd, `${header}\n`);
  fs.writeSync(fd, text);
  if (!text.endsWith('\n')) fs.writeSync(fd, '\n');
  fs.writeSync(fd, '\n');
}

function tryReadFileWithVnxPatch(abs, debug, sampleSkipped) {
  try {
    return fs.readFileSync(abs);
  } catch (e) {
    const msg = String(e?.message || e);
    if (/EACCES|permission denied/i.test(msg)) {
      try { fs.chmodSync(abs, 0o644); } catch {}
      try {
        return fs.readFileSync(abs);
      } catch (e2) {
        const msg2 = String(e2?.message || e2);
        if (sampleSkipped && sampleSkipped.length < 30) sampleSkipped.push({ reason: 'read_eacces', file: abs, err: msg2.slice(0, 140) });
        if (debug) debug.warnings.push(`read denied even after chmod: ${abs}: ${msg2}`);
        return null;
      }
    }
    if (sampleSkipped && sampleSkipped.length < 30) sampleSkipped.push({ reason: 'read_failed', file: abs, err: msg.slice(0, 140) });
    if (debug) debug.warnings.push(`read failed: ${abs}: ${msg}`);
    return null;
  }
}

function classifyPeripheryHit(relOrAbs) {
  const t = s(relOrAbs).toLowerCase();
  if (/(psu|power[-_ ]?suppl)/.test(t)) return 'power';
  if (/(fans?|fan[-_ ]?control)/.test(t)) return 'fans';
  if (/(sfp|transceiver|ports?)/.test(t)) return 'sfp_ports';
  return '';
}

function buildCombinedToFile(filesAbs, rootAbs, debug, outPath) {
  const ordered = sortCandidatesForCombine(filesAbs);
  const fd = fs.openSync(outPath, 'w');

  const stats = {
    scannedFiles: 0,
    includedFiles: 0,
    skippedByHardExt: 0,
    skippedBinaryHeuristic: 0,
    skippedEmptyText: 0,
    readErrors: 0,
  };

  const includedSamples = [];
  const skippedSamples = [];
  const orderedTop = [];
  const peripheryPriorityFiles = [];
  const peripheryIncluded = { power: 0, fans: 0, sfp_ports: 0 };
  const peripheryInHead = { power: 0, fans: 0, sfp_ports: 0 };
  let charsWritten = 0;

  const seen = new Set();

  try {
    for (const abs of ordered) {
      const key = path.resolve(abs);
      if (seen.has(key)) continue;
      seen.add(key);

      let st;
      try { st = fs.statSync(abs); } catch { continue; }
      if (!st.isFile() || st.size <= 0) continue;

      if (orderedTop.length < 60) {
        orderedTop.push({
          file: path.relative(rootAbs, abs),
          size: st.size,
          score: scoreTextCandidate(abs),
        });
      }

      stats.scannedFiles++;

      const ext = extLower(abs);
      if (isHardBinaryExt(ext)) {
        stats.skippedByHardExt++;
        if (skippedSamples.length < 30) skippedSamples.push({ reason: 'hard_ext', file: abs });
        continue;
      }

      const buf = tryReadFileWithVnxPatch(abs, debug, skippedSamples);
      if (!buf) { stats.readErrors++; continue; }

      if (isProbablyBinary(buf)) {
        stats.skippedBinaryHeuristic++;
        if (skippedSamples.length < 30) skippedSamples.push({ reason: 'binary_heuristic', file: abs });
        continue;
      }

      const text = decodeSmart(buf);
      if (!text.trim()) {
        stats.skippedEmptyText++;
        if (skippedSamples.length < 30) skippedSamples.push({ reason: 'empty_text', file: abs });
        continue;
      }

      const rel = path.relative(rootAbs, abs);
      const header = `===== FILE: ${rel} (size=${st.size}) =====\n`;
      const body = text.endsWith('\n') ? text : (text + '\n');
      const trailer = '\n';
      const blockChars = header.length + body.length + trailer.length;

      fs.writeSync(fd, header);
      fs.writeSync(fd, body);
      fs.writeSync(fd, trailer);

      stats.includedFiles++;
      charsWritten += blockChars;

      const pClass = classifyPeripheryHit(rel);
      if (pClass) {
        peripheryIncluded[pClass]++;
        if (peripheryPriorityFiles.length < 40) peripheryPriorityFiles.push({ file: rel, size: st.size, score: scoreTextCandidate(abs), kind: pClass });
        if (charsWritten <= LLM4_HEAD_HINT_CHARS) peripheryInHead[pClass]++;
      }

      if (includedSamples.length < 30) includedSamples.push({ file: rel, size: st.size });
    }
  } finally {
    fs.closeSync(fd);
  }

  const bytesOnDisk = (() => { try { return fs.statSync(outPath).size; } catch { return 0; } })();

  return {
    bytesOnDisk,
    stats,
    includedSamples,
    skippedSamples,
    orderedTop,
    peripheryPriorityFiles,
    peripheryIncluded,
    peripheryInHead,
    combinedCharsApprox: charsWritten,
  };
}

// ---------------- source attachment pick ----------------

function pickSourceAttachment() {
  const preId = normalizeFileId(base.sourceFileId || base._collector_sourceFileId || '');
  const preName = safeName(base.sourceFileName || base.archiveName || 'attachment.bin');

  let files = base.files;
  if (typeof files === 'string') {
    try { files = JSON.parse(files); } catch { files = null; }
  }
  if (!Array.isArray(files)) files = [];

  const nonImage = files.filter(f => String(f?.kind || '').toLowerCase() !== 'image');

  if (preId) {
    const match = nonImage.find(f => normalizeFileId(f.file_id || f.id) === preId);
    if (match) {
      return {
        file_id: preId,
        name: safeName(match.name || preName),
        size: Number(match.size || 0),
        pickedBy: 'base.sourceFileId',
      };
    }
    return {
      file_id: preId,
      name: preName,
      size: 0,
      pickedBy: 'base.sourceFileId_fallback',
    };
  }

  if (!nonImage.length) return null;

  const sorted = nonImage.slice().sort((a, b) => Number(b.size || 0) - Number(a.size || 0));
  const pick = sorted[0] || nonImage[0];

  return {
    file_id: normalizeFileId(pick.file_id || pick.id),
    name: safeName(pick.name || 'attachment.bin'),
    size: Number(pick.size || 0),
    pickedBy: 'largest_non_image',
  };
}

// ---------------- main ----------------

async function main() {
  if (!UNZIP_PACK_URL) throw new Error('UNZIP_PACK_URL не задан');

  ensureDir(DL_DIR);
  ensureDir(EX_DIR);
  ensureDir(ALIAS_DIR);
  ensureDir(OUT_ROOT);

  const debug = {
    runId,
    getFileTries: [],
    warnings: [],
    unzipPack: [],
    sizes: {},
    combine: {},
  };

  const src = pickSourceAttachment();
  if (!src) throw new Error('Во входящем сообщении нет не-графических вложений для разбора.');
  if (!src.file_id) throw new Error('Не удалось определить file_id вложения. Переотправьте архив одним файлом.');

  debug.pick = {
    pickedBy: src.pickedBy,
    file_id: src.file_id,
    name: src.name,
    size: src.size,
  };

  const dlPath = path.join(DL_DIR, src.name);
  const dlBytes = await yandexDownloadFileToPath(src.file_id, dlPath, debug);
  debug.sizes.downloaded_bytes = Number(dlBytes || 0);
  debug.sizes.download_path = dlPath;

  // BFS extraction (nested)
  const q = [{ abs: dlPath, depth: 0, parent: EX_DIR }];
  const visited = new Set();
  const extractedRoots = new Set();

  while (q.length) {
    const cur = q.shift();
    if (!cur || !cur.abs) continue;

    const abs = path.resolve(cur.abs);
    const key = `${cur.depth}:${abs}`;
    if (visited.has(key)) continue;
    visited.add(key);

    if (cur.depth > MAX_DEPTH) continue;
    if (!isArchiveCandidate(abs)) continue;

    const targetDir = path.join(cur.parent, safeName(path.basename(abs)) + '_dir');
    ensureDir(targetDir);

    const alias = ensureArchiveAliasForTools(abs, ALIAS_DIR);
    const r = await unzipPackExtract(alias.usePath, targetDir, debug);

    debug.unzipPack.push({
      depth: cur.depth,
      src: path.basename(abs),
      use: path.basename(alias.usePath),
      magic: alias.magic || '',
      aliased: !!alias.aliased,
      ok: !!r.ok,
      engine: r.engine || '',
      code: Number(r.code || 0),
      file_count: Number(r.file_count || 0),
      timeout: !!r.timeout,
      too_many_files: !!r.too_many_files,
    });
    if (debug.unzipPack.length > 120) debug.unzipPack.shift();

    if (!r.ok) continue;

    // VNX minipatch: fix perms so combine can read
    chmodTreeSafe(targetDir, debug);

    extractedRoots.add(targetDir);

    const filesAbs = listFilesRecursive(targetDir, NESTED_ENUM_CAP);
    for (const f of filesAbs) {
      if (cur.depth + 1 <= MAX_DEPTH) q.push({ abs: f, depth: cur.depth + 1, parent: targetDir });
    }
  }

  // Candidate files for combine
  let allFiles = [];
  if (extractedRoots.size) {
    const roots = Array.from(extractedRoots);
    allFiles = collectFilesFromRoots(roots, Math.min(COMBINE_SCAN_MAX_FILES, NESTED_ENUM_CAP));
    debug.sizes.extracted_root_count = roots.length;
    debug.sizes.combine_candidate_files = allFiles.length;
  } else {
    allFiles = [dlPath];
    debug.sizes.extracted_root_count = 0;
    debug.sizes.combine_candidate_files = 1;
  }

  const outDir = path.join(OUT_ROOT, crypto.createHash('sha1').update(runId).digest('hex').slice(0, 16));
  ensureDir(outDir);

  const archiveBase = safeName(
    (base.archiveName || base.sourceFileName || src.name)
      .replace(/\.(zip|7z|tgz|tar\.gz|gz|tar|tbz2|tbz|tar\.bz2|bz2|xz|txz|tar\.xz|zst|tzst|tar\.zst)$/i, '')
  ) || 'combined';

  const combinedName = `${archiveBase}.txt`;
  const combinedPath = path.join(outDir, combinedName);

  const rootAbs = extractedRoots.size ? Array.from(extractedRoots)[0] : DL_DIR;
  const c = buildCombinedToFile(allFiles, rootAbs, debug, combinedPath);

  debug.combine = {
    combined_written_files: c.stats.includedFiles,
    combined_bytes: c.bytesOnDisk,
    combined_chars_approx: c.combinedCharsApprox,
    llm4_head_hint_chars: LLM4_HEAD_HINT_CHARS,
    stats: c.stats,
    periphery_included: c.peripheryIncluded,
    periphery_in_head_hint: c.peripheryInHead,
    top_ordered_candidates: c.orderedTop,
    periphery_priority_files: c.peripheryPriorityFiles,
    included_samples: c.includedSamples,
    skipped_samples: c.skippedSamples,
  };

  debug.sizes.combined_path = combinedPath;

  const identifyEvidenceName = `${archiveBase}__identify_evidence.txt`;
  const identifyEvidencePath = path.join(outDir, identifyEvidenceName);
  try { fs.linkSync(combinedPath, identifyEvidencePath); }
  catch { fs.copyFileSync(combinedPath, identifyEvidencePath); }

  return [{
    json: {
      ...base,

      _collector_ok: true,
      _collector_error: '',
      _collector_sourceFileId: src.file_id,
      _collector_sourceFileName: src.name,

      _collector_debug: {
        runId,
        pick: debug.pick,
        warnings: debug.warnings.slice(0, 140),
        extracted_roots: Array.from(extractedRoots).slice(0, 12),
        unzip_pack_url: UNZIP_PACK_URL,
        unzip_pack_calls: debug.unzipPack.slice(-80),
        chmod_touched: debug.chmod_touched || null,
        sizes: debug.sizes,
        combine: debug.combine,
      },

      combinedLogPath: combinedPath,
