const SFP_T1_MAX = Number($env.LLM4_SFP_T1_MAX_LINES || 1800);
const PSU_T2_MAX = Number($env.LLM4_PSU_T2_MAX_LINES || 900);
const SFP_T2_MAX = Number($env.LLM4_SFP_T2_MAX_LINES || 1100);

function ensureDir(p){ try { fs.mkdirSync(p, { recursive:true }); } catch {} }
