  try {
    if (!fs.existsSync(root)) return;
    const now = Date.now();
    for (const name of fs.readdirSync(root)) {
      const p = path.join(root, name);
      let st;
      try { st = fs.statSync(p); } catch { continue; }
      if (!st.isDirectory()) continue;
      const ageH = (now - st.mtimeMs) / 3600000;
      if (ageH > ttlHours) {
