// ----- field detectors -----
const RX_SERIAL = /\b(serial\s*number|serial|s\/n|sn\b)\b/i;
const RX_PART   = /\b(part\s*number|part|p\/n|pn\b|fru)\b/i;
const RX_WATT   = /\b(watt|watts|ratedpower|\b\d{2,4}\s*w\b)\b/i;
