const RX_IBM_PSU = /\b(PSU_count|PSU_id|PSU_status|PSU_serial_number|PSU_FRU|PL_VPD_NODE_PSU_FRU_PN|node_FRU_part|FRU_part_number|lsenclosurecanister|lsenclosureslot|lsenclosurepsu)\b/i;

// 3PAR
const RX_3PAR_PSUFAN_HDR = /\bPS\s+PSState\s+ACState\s+DCState\s+Fan State\s+Fan0_Speed\s+Fan1_Speed\b/i;
