// ----- command block helpers -----
function isAnyShow(t){ return /(?:^|\s)#\s+show\s+/i.test(t); }
function isExitLine(t){ return /(?:^|\s)#\s+exit\b/i.test(t); }
function isCmd(t, cmdWord){
