function isPsuCmd(t){
  return isCmd(t, 'power-supplies') || isCmd(t, 'power-supply') || isCmd(t, 'psu');
}
function isPortsCmd(t){
  return isCmd(t, 'ports') || isCmd(t, 'port');
}

// ----- Tier1 anchors -----
const PSU_T1_ANCHORS = [
  /^#\s+show\s+power-supplies\b/i,
  /^Encl\s+Id\s+Serial\s+Number/i,
  /\bPower\s+Supply\/Cooling\s+Fan\s+module\b/i,
