        if (isPsuCmd(t) && !blocks.psu.on) {
          blocks.psu.on = true;
          blocks.psu.lines.push('# show power-supplies');
        }
        if (isPortsCmd(t) && !blocks.ports.on) {
          blocks.ports.on = true;
          blocks.ports.lines.push('# show ports');
