        const isExit = isExitLine(t);

        if (blocks.psu.on) {
          if ((isAnyShow(t) && !isPsuCmd(t)) || isExit) blocks.psu.on = false;
          else addBlockLine(blocks.psu, t);
        }
        if (blocks.ports.on) {
          if ((isAnyShow(t) && !isPortsCmd(t)) || isExit) blocks.ports.on = false;
          else addBlockLine(blocks.ports, t);
        }

        if (PSU_T1_ANCHORS.some(rx => rx.test(t)) || isPsuInventoryLine(t)) {
          dedupPush(psu_t1, cP1, t, PSU_T1_MAX);
        }
        if (SFP_T1_ANCHORS.some(rx => rx.test(t)) || isSfpInventoryLine(t)) {
