  /\b(Battery_count|Battery_id|Battery_status|Battery_FRU_part|Battery_cycle_count|Battery_power_on_hours|Battery_charging_status)\s*[:=]/i,
  /\bec_bbu_init\b/i,
  /\bbattery_charging\b/i,
  /\bCapacitor\s+Charge\b/i,
  /\bChargeState\b/i,
  /\bDeliverableCapacity\b/i,
  RX_HW_BBU,
  RX_IBM_BBU,
  RX_SPS,
  /\bBattery\s+State\s*:\s*(OK|Good|Failed|N\/A)\b/i,
