  /^Name\s+Location\s+Status/i,
  /\bFan\s+ID\s*:\b/i,
  /\bFan\s+State\s*:\s*(OK|Good|Failed|N\/A)\b/i,
  /\bfan\b.*\b(rpm|speed|tach|pwm)\b/i,
  RX_IBM_FAN,
  RX_3PAR_FAN,
  RX_HW_FAN,
