function isBbuInventoryLine(line){
  const t = s(line);
  const hasBbuContext =
    RX_BBU_TOK.test(t) ||
    RX_IBM_BBU.test(t) ||
    RX_HW_BBU.test(t) ||
    RX_SPS.test(t) ||
    /Capacitor\s+Charge|ChargeState|DeliverableCapacity/i.test(t);

