    RX_CHARGE.test(t) ||
    RX_CAP.test(t) ||
    RX_AGE.test(t) ||
    RX_TEMP.test(t) ||
    RX_SERIAL.test(t) ||
    RX_PART.test(t) ||
    RX_HEALTH.test(t) ||
    RX_IBM_BBU.test(t)
