}

function isFanInventoryLine(line){
  const t = s(line);
  const hasFanContext =
    RX_FAN_TOK.test(t) ||
    RX_IBM_FAN.test(t) ||
    RX_3PAR_FAN.test(t) ||
    RX_HW_FAN.test(t) ||
