// ----- Tier2 queries -----
const BBU_T2_QUERIES = [
  { key:'bbu_serial', rx:/\b(bbu|battery|supercap|capacitor|cap-pack|sps|ups)\b.*\b(serial\s*number|s\/n|sn\b)\b/i },
