async function scan(filePath){
  return await new Promise((resolve, reject) => {
    const rs = fs.createReadStream(filePath, { encoding:'utf8' });

    let bytesRead = 0, linesRead = 0;
    let buf = '';

    const blocks = {
      bbu:  { on:false, lines: [] },
      fans: { on:false, lines: [] },
    };

    const bbu_t1 = [], fan_t1 = [];
    const bbu_t2 = [], fan_t2 = [];
    const cB1 = new Map(), cF1 = new Map(), cB2 = new Map(), cF2 = new Map();
    const t2BCounts = new Map(), t2FCounts = new Map();

    function addBlockLine(bucket, line){
      if (bucket.lines.length < MAX_BLOCK_LINES) bucket.lines.push(line);
    }

    rs.on('data', (chunk) => {
      bytesRead += Buffer.byteLength(chunk, 'utf8');
      buf += chunk;

      let idx;
      while ((idx = buf.indexOf('\n')) >= 0) {
        const raw = buf.slice(0, idx);
        buf = buf.slice(idx + 1);

        linesRead++;
        const line = stripSourcePrefix(raw);
        if (!line || isNoise(line)) {
          if (MAX_SCAN_BYTES > 0 && bytesRead > MAX_SCAN_BYTES) { try { rs.destroy(); } catch {} }
          continue;
        }

        const t = line;

        if (isBbuCmd(t) && !blocks.bbu.on) {
          blocks.bbu.on = true;
          blocks.bbu.lines.push('# show bbus');
        }
        if (isFansCmd(t) && !blocks.fans.on) {
          blocks.fans.on = true;
          blocks.fans.lines.push('# show fans');
        }

        const isExit = isExitLine(t);

        if (blocks.bbu.on) {
          if ((isAnyShow(t) && !isBbuCmd(t)) || isExit) blocks.bbu.on = false;
          else addBlockLine(blocks.bbu, t);
        }
        if (blocks.fans.on) {
          if ((isAnyShow(t) && !isFansCmd(t)) || isExit) blocks.fans.on = false;
          else addBlockLine(blocks.fans, t);
        }

        if (BBU_T1_ANCHORS.some(rx => rx.test(t)) || isBbuInventoryLine(t)) {
          dedupPush(bbu_t1, cB1, t, BBU_T1_MAX);
        }
        if (FAN_T1_ANCHORS.some(rx => rx.test(t)) || isFanInventoryLine(t)) {
          dedupPush(fan_t1, cF1, t, FAN_T1_MAX);
        }

        const kB = matchTier2(t, BBU_T2_QUERIES);
        if (kB && allowT2(t2BCounts, kB)) {
          const ok =
            RX_BBU_TOK.test(t) ||
            RX_IBM_BBU.test(t) ||
            RX_HW_BBU.test(t) ||
            RX_SPS.test(t) ||
            /Capacitor\s+Charge|ChargeState|DeliverableCapacity/i.test(t);
          if (ok) dedupPush(bbu_t2, cB2, t, BBU_T2_MAX);
        }

        const kF = matchTier2(t, FAN_T2_QUERIES);
        if (kF && allowT2(t2FCounts, kF)) {
          const ok =
            RX_FAN_TOK.test(t) ||
            RX_IBM_FAN.test(t) ||
            RX_3PAR_FAN.test(t) ||
            RX_HW_FAN.test(t) ||
            RX_COOLING_MODULE.test(t);
          if (ok) dedupPush(fan_t2, cF2, t, FAN_T2_MAX);
        }

        if (MAX_SCAN_BYTES > 0 && bytesRead > MAX_SCAN_BYTES) {
          try { rs.destroy(); } catch {}
          break;
        }
      }
    });

    rs.on('close', () => {
      resolve({
        bytesRead,
        linesRead,
        bbuBlock: blocks.bbu.lines.join('\n').trim(),
        fansBlock: blocks.fans.lines.join('\n').trim(),
        bbu_t1,
        fan_t1,
        bbu_t2,
        fan_t2,
        tier2_bbu_counts: Object.fromEntries(t2BCounts),
        tier2_fan_counts: Object.fromEntries(t2FCounts),
      });
    });

    rs.on('error', (e) => reject(e));
  });
}

