function stripThink(text) {
  let t = s(text);
  t = t.replace(/<think\b[^>]*>[\s\S]*?<\/think>/gi, '');
  t = t.replace(/<think\b[^>]*>[\s\S]*$/gi, '');
  return t;
}
function stripCodeFences(text) {
  let t = s(text).trim();
  const fenced = t.match(/```(?:[a-zA-Z0-9_-]+)?\s*([\s\S]*?)```/);
  if (fenced) t = s(fenced[1]).trim();
  t = t.replace(/^\s*```.*$/gm, '').trim();
  return t;
}
function normalizeTableName(line){
  const t = s(line).trim();
  if (/^TABLE:\s*BBU\b/i.test(t))  return 'BBU';
  if (/^TABLE:\s*Fans\b/i.test(t)) return 'Fans';
  return '';
}
function isLikelyRow(line){
  const t = s(line).trim();
  if (!t) return false;
  if (/^TABLE:/i.test(t)) return false;
  return t.includes(';') || /^N\/A$/i.test(t);
}
function isHeaderRow(line, table){
  const t = s(line).trim().toLowerCase();
  if (!t.includes(';')) return false;
  if (table === 'BBU') return t.includes('serial_number') || t.includes('capacity') || t.includes('temperature');
  if (table === 'Fans') return t.includes('part_number') || t.includes('model') || t.includes('health');
  return false;
}
function finalizeTable(rows, printed){
  const key = printed.replace(/^TABLE:\s*/i,'').trim();
  const clean = rows.filter(Boolean);
  if (!clean.length) return [printed, 'N/A'];
  if (clean.some(r => /^N\/A$/i.test(r))) return [printed, 'N/A'];
  if (clean.length === 1 && isHeaderRow(clean[0], key)) return [printed, 'N/A'];
  if (isHeaderRow(clean[0], key)) {
    const hasData = clean.slice(1).some(r => r.includes(';'));
    if (!hasData) return [printed, 'N/A'];
  }
  return [printed, ...clean];
}
function normalizeOutput(raw){
  let t = stripCodeFences(stripThink(raw)).replace(/\r/g,'').trim();
  if (!t) return ['TABLE: BBU','N/A','','TABLE: Fans','N/A'].join('\n');
  if (t.length > HARD_MAX_OUT_CHARS) t = t.slice(0, HARD_MAX_OUT_CHARS) + '\n[n8n] TRUNCATED';

  const lines = t.split('\n').map(x => x.trim()).filter(Boolean);
  const sec = { BBU: [], Fans: [] };
  let cur = '';

  for (const line of lines) {
    const tn = normalizeTableName(line);
    if (tn) { cur = tn; continue; }
    if (!cur) continue;
    if (!isLikelyRow(line)) continue;
    sec[cur].push(/^N\/A$/i.test(line) ? 'N/A' : line);
  }

  return [
    ...finalizeTable(sec.BBU, 'TABLE: BBU'),
    '',
    ...finalizeTable(sec.Fans, 'TABLE: Fans'),
  ].join('\n').trim();
}
function pickMeta(resp) {
  const o = resp || {};
  return {
    model: o.model,
    created_at: o.created_at,
    done: o.done,
    done_reason: o.done_reason,
    total_duration: o.total_duration,
    load_duration: o.load_duration,
    prompt_eval_count: o.prompt_eval_count,
    prompt_eval_duration: o.prompt_eval_duration,
    eval_count: o.eval_count,
    eval_duration: o.eval_duration,
  };
}
function prune(out) {
  const drop = ['messages','llm_input','chatInput','prompt','digest_bbu_fan_text','docs_context','event_catalog_context','logsCombined','combinedLogs','logDigest','logDigestText'];
  for (const k of drop) if (k in out) delete out[k];
  return out;
}

async function main() {
  const inputPath = s(base.llm5_input_path).trim();
  const filePrompt = safeReadUtf8(inputPath);

  const fallbackPrompt =
    s(base.llm_input) || s(base.prompt) || s(base.chatInput) || s(base.digest_bbu_fan_text) ||
    'TASK: STORAGE INVENTORY — BBU + FANS\nTABLE: BBU\nN/A\n\nTABLE: Fans\nN/A';

  const userPrompt = s(filePrompt || fallbackPrompt).trim();

  const model = 'deepseek-logs:latest';

  const STRICT_SYSTEM = [
    'ROLE: TABLE EXTRACTOR (NOT A CHATBOT).',
    'PRIORITY: Tier 1 evidence is HIGH TRUST. Use Tier 1 first. Tier 2 only if needed.',
    'Return ONLY 2 tables in this exact order:',
    'TABLE: BBU',
    'TABLE: Fans',
    'NO reasoning, NO explanations, NO markdown fences, NO extra text.',
    'If a table has 0 rows, output ONLY "N/A" under that table (no header row).',
    'If you output a header, you MUST output >=1 data row.',
    'Universal schema:',
    'BBU: location;serial_number;part_number;capacity;charge;age;temperature;health',
    'Fans: location;part_number;model;health',
    'If a column is N/A for all rows, omit it.',
    'Do not add anything before or after the tables.'
  ].join('\n');

  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url,
      headers: { 'Content-Type': 'application/json' },
      json: true,
      body: {
        model,
        stream: false,
        messages: [
          { role: 'system', content: STRICT_SYSTEM },
          { role: 'user', content: userPrompt },
        ],
        options: {
          temperature: 0,
          top_k: 1,
          top_p: 1,
          num_ctx: 65536,
          num_predict: 8192,
          repeat_penalty: Number($env.STORAGE_REPEAT_PENALTY || 1.08),
        },
      },
      timeout: 60 * 60 * 1000,
    });

    const rawContent =
      (resp && resp.message && typeof resp.message.content === 'string') ? resp.message.content :
      (typeof resp?.response === 'string') ? resp.response :
      JSON.stringify(resp);

    const normalized = normalizeOutput(rawContent);

    const out = {
      ...base,
      model,
      ollama_bbu_fan: { ...pickMeta(resp), preview: s(rawContent).replace(/\s+/g, ' ').slice(0, 400) },
      bbu_fan_raw: normalized,
      message: { role: 'assistant', content: normalized },
      _llm5_request_mode: 'file_first_strict_system',
      _llm5_input_source: filePrompt ? 'llm5_input_path' : 'fallback_json',
      _llm5_input_path_ok: !!filePrompt,
      _llm5_input_chars: userPrompt.length,
      _llm5_output_cap: HARD_MAX_OUT_CHARS,
    };

    prune(out);
    return [{ json: out }];
  } catch (e) {
    const status = e?.response?.status || e?.statusCode || '';
    const data = e?.response?.data ? JSON.stringify(e.response.data).slice(0, 2000) : '';
    const msg = `[LLM5 ERROR] status=${status} ${s(e?.message || e)}`;

    const out = {
      ...base,
      model,
      bbu_fan_raw: ['TABLE: BBU','N/A','','TABLE: Fans','N/A'].join('\n'),
      message: { role: 'assistant', content: msg },
      _llm_error: true,
      _llm_error_status: status,
      _llm_error_data: data,
      _llm5_request_mode: 'file_first_strict_system',
    };

    prune(out);
    return [{ json: out }];
  }
}

return await main();
